// farm_management_system/savanna_farm_suite/doctype/cattle/cattle_list.js
frappe.listview_settings['Cattle'] = {
    refresh: function (list_view) {
        list_view.page.add_inner_button(__('Make Collection'), () => {
            const dialog = new frappe.ui.Dialog({
                title: __('Make a Collection of Animal Products'),
                fields: [
                    { fieldtype: 'Date', fieldname: 'date_of_collection', label: __('Date of Collection'), default: frappe.datetime.get_today(), reqd: 1 },
                    // { fieldtype: 'Time', fieldname: 'time_of_collection', label: __('Time of Collection'), default: frappe.datetime.now_time(), reqd: 1 },
                    { fieldtype: 'Link', fieldname: 'animal', label: __('Specify Animal'), options: 'Animals', default: "Cattle", reqd: 1 },
                    { fieldtype: 'Check', fieldname: 'is_animal_specific', label: __('Is Animal Specific?'), default: 1 },
                    { fieldtype: 'Check', fieldname: 'is_shed_specific', label: __('Is Shed Specific?'), default: 0 },
                    // { fieldtype: 'Link', fieldname: 'cattle', label: __('Specify Cow'), options: 'Cattle', description: __('NOTE: Only Use for a single Cow if Applicable.'), depends_on: 'eval:doc.is_animal_specific==1' },
                    { fieldtype: 'Link', fieldname: 'cattle_shed', label: __('Specify Cattle Shed'), options: 'Cattle Shed', description: __('Select a shed to collect for ALL animals in it.'), depends_on: 'eval:doc.is_shed_specific==1' },
                    {
                        fieldtype: 'Table',
                        fieldname: 'production_table',
                        label: __('Collections Table'),
                        description: __('Use this table for <b>Multiple Entries</b>'),
                        depends_on: 'eval:doc.is_animal_specific==1',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'cattle', label: __('Cow'), options: 'Cattle', in_list_view: 1 },
                            // { fieldtype: 'Data', fieldname: 'cattle_nickname', label: __('Nickname'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Time', fieldname: 'time_of_collection', label: __('Time of Collection'), default: frappe.datetime.now_time(), in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'milker', label: __('Milker'), options: 'Employee', in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            // { fieldtype: 'Data', fieldname: 'default_uom', label: __('Default UOM'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_collected', label: __('Quantity Collected'), reqd: 1, in_list_view: 1 }
                        ]
                    },
                    {
                        fieldtype: 'Table',
                        fieldname: 'shed_production_table',
                        label: __('Shed Collections Table'),
                        description: __('Use this table for <b>Shed-based Entries</b>'),
                        depends_on: 'eval:doc.is_shed_specific==1',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'cattle_shed', label: __('Cattle Shed'), options: 'Cattle Shed', in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'shed_info', label: __('Shed Info'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Time', fieldname: 'time_of_collection', label: __('Time of Collection'), default: frappe.datetime.now_time(), in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'milker', label: __('Milker'), options: 'Employee', in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            // { fieldtype: 'Data', fieldname: 'default_uom', label: __('Default UOM'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_collected', label: __('Quantity Collected'), reqd: 1, in_list_view: 1 }
                        ]
                    }
                ],
                primary_action_label: __('Make Entry'),
                primary_action: function () {
                    const dvalues = dialog.get_values(true);
                    const today = frappe.datetime.get_today();
                    const selected_date = dvalues && dvalues.date_of_collection;
                    if (selected_date && selected_date > today) {
                        frappe.show_alert({ message: __('Date of Collection cannot be a future date.'), indicator: 'orange' }, 5);
                        return;
                    }

                    const is_shed = dvalues.is_shed_specific;
                    const rows = is_shed ? (dvalues.shed_production_table || []) : (dvalues.production_table || []);
                    const normalized_rows = (rows || []).map(row => ({
                        ...row,
                        time_of_collection: row.time_of_collection || dvalues.time_of_collection
                    }));
                    if (!normalized_rows.length) {
                        frappe.show_alert({ message: __('No products found to collect.'), indicator: 'orange' }, 5);
                        return;
                    }

                    frappe.warn(
                        __('Are you sure you want to proceed?'),
                        __('Please Note this Action is Irreversible'),
                        () => {
                            frappe.dom.freeze(__('Creating collection...'));
                            frappe.call({
                                method: 'farm_management_system.savanna_farm_suite.doctype.cattle.cattle.create_collection_entry',
                                args: {
                                    cattle: is_shed ? null : (dvalues.cattle || null),
                                    date_of_collection: dvalues.date_of_collection,
                                    rows: normalized_rows
                                },
                                callback: function (r) {
                                    frappe.dom.unfreeze();
                                    if (!r.exc && r.message) {
                                        // Play custom success sound
                                        var audio = new Audio('/assets/farm_management_system/sounds/success.mp3');
                                        audio.play().catch(function () { frappe.utils.play_sound('submit'); });
                                        dialog.hide();
                                        list_view.refresh();
                                        frappe.show_alert({ message: __('Collection recorded'), indicator: 'green' }, 5);
                                    } else if (r.exc) {
                                        // Play custom error sound
                                        var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                        errAudio.play().catch(function () { });
                                        const errMsg = (typeof r.exc === 'string') ? r.exc : (r._server_messages || r.exc || __('Unknown error occurred'));
                                        frappe.show_alert({ message: __('Error: ') + errMsg, indicator: 'red' }, 10);
                                    }
                                },
                                error: function () {
                                    frappe.dom.unfreeze();
                                    // Play custom error sound
                                    var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                    errAudio.play().catch(function () { });
                                    frappe.show_alert({ message: __('Network Error: Please try again.'), indicator: 'red' }, 10);
                                }
                            });
                        },
                        'Continue',
                        true
                    );
                }
            });

            dialog.show();
            dialog.$wrapper.find('.modal-dialog').addClass('modal-lg');

            // ───── Mutual exclusion for checkboxes ─────
            dialog.fields_dict.is_animal_specific.$input.on('change', function () {
                if (dialog.get_value('is_animal_specific')) {
                    dialog.set_value('is_shed_specific', 0);
                }
            });
            dialog.fields_dict.is_shed_specific.$input.on('change', function () {
                if (dialog.get_value('is_shed_specific')) {
                    dialog.set_value('is_animal_specific', 0);
                }
            });

            // ───── Helper: apply per-row + top-level query so animal_product only shows products for selected animal ─────
            function set_product_query_for_animal(animal_name) {
                const get_query_fn = function () {
                    if (!animal_name) return { filters: {} };
                    return { filters: { product_tied_to_which_animal: animal_name } };
                };

                // Apply to animal-specific table
                _apply_product_query_to_table(dialog.fields_dict.production_table, get_query_fn);
                // Apply to shed-specific table
                _apply_product_query_to_table(dialog.fields_dict.shed_production_table, get_query_fn);
            }

            function _apply_product_query_to_table(tbl, get_query_fn) {
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                try {
                    if (typeof grid.get_field === 'function') {
                        const topField = grid.get_field('animal_product');
                        if (topField) {
                            topField.get_query = get_query_fn;
                            if (topField.df) topField.df.get_query = get_query_fn;
                        }
                    }
                } catch (e) { console.warn('set_product_query top set failed', e); }

                try {
                    (grid.grid_rows || []).forEach(function (gr) {
                        try {
                            const f = gr.fields_map && gr.fields_map.animal_product;
                            if (f) {
                                f.get_query = get_query_fn;
                                if (f.df) f.df.get_query = get_query_fn;
                                if (gr.doc && gr.doc.animal_product) {
                                    gr.doc.animal_product = '';
                                    if (gr.refresh_field) gr.refresh_field('animal_product');
                                }
                            }
                        } catch (inner) { /* ignore per-row errors */ }
                    });
                } catch (e) { console.warn('set_product_query per-row set failed', e); }

                try { grid.refresh(); } catch (e) { }
            }

            // ───── Helper: populate rows for all active cattle (has_been_culled == 0) ─────
            function populate_rows_for_all_cattle() {
                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Cattle',
                        filters: { has_been_culled: 0 },
                        fields: ['name', 'add_nickname_optional'],
                        limit_page_length: 2000
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (tbl.grid) tbl.grid.refresh();
                            frappe.show_alert({ message: __('No active Cattle found'), indicator: 'orange' }, 5);
                            return;
                        }

                        const rows = r.message.map(c => ({
                            cattle: c.name,
                            cattle_nickname: c.add_nickname_optional || '',
                            time_of_collection: frappe.datetime.now_time(),
                            milker: '',
                            animal_product: '',
                            default_uom: '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                grid.grid_rows.forEach(function (gr) {
                                    try {
                                        if (gr.fields_map && gr.fields_map.cattle) {
                                            gr.fields_map.cattle.df.read_only = 1;
                                            gr.fields_map.cattle.$input && gr.fields_map.cattle.$input.prop('readonly', true);
                                        }
                                        if (gr.fields_map && gr.fields_map.cattle_nickname) {
                                            gr.fields_map.cattle_nickname.df.read_only = 1;
                                            gr.fields_map.cattle_nickname.$input && gr.fields_map.cattle_nickname.$input.prop('readonly', true);
                                        }
                                        gr.toggle_remove_button && gr.toggle_remove_button(false);
                                    } catch (e) { }
                                });
                            }
                            dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                        } catch (e) {
                            console.warn('Could not lock child rows after cattle populate', e);
                        }

                        set_product_query_for_animal(dialog.get_value('animal'));
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Cattle'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── Helper: populate rows from list of Animal Products (one row per product) ─────
            function populate_rows_from_products_for_animal(animal) {
                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Animal Products',
                        filters: { product_tied_to_which_animal: animal },
                        fields: ['name', 'default_unit_of_measure'],
                        limit_page_length: 500
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (grid) grid.refresh();
                            frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' }, 5);
                            return;
                        }

                        const products = r.message;
                        const rows = products.map(p => ({
                            cattle: '',
                            cattle_nickname: '',
                            time_of_collection: frappe.datetime.now_time(),
                            milker: '',
                            animal_product: p.name,
                            default_uom: p.default_unit_of_measure || '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').show();
                        if (grid.grid_rows && grid.grid_rows.length) {
                            grid.grid_rows.forEach(function (gr) {
                                try {
                                    if (gr.fields_map && gr.fields_map.cattle) {
                                        gr.fields_map.cattle.df.read_only = 0;
                                        gr.fields_map.cattle.$input && gr.fields_map.cattle.$input.prop('readonly', false);
                                        gr.toggle_remove_button && gr.toggle_remove_button(true);
                                    }
                                    if (gr.fields_map && gr.fields_map.cattle_nickname) {
                                        gr.fields_map.cattle_nickname.df.read_only = 1;
                                        gr.fields_map.cattle_nickname.$input && gr.fields_map.cattle_nickname.$input.prop('readonly', true);
                                    }
                                } catch (e) { }
                            });
                        }

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── Helper: populate shed table rows from products ─────
            function populate_shed_rows_from_products(animal) {
                const tbl = dialog.fields_dict.shed_production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Animal Products',
                        filters: { product_tied_to_which_animal: animal },
                        fields: ['name', 'default_unit_of_measure'],
                        limit_page_length: 500
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (grid) grid.refresh();
                            frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' }, 5);
                            return;
                        }

                        const products = r.message;
                        const rows = products.map(p => ({
                            cattle_shed: '',
                            shed_info: '',
                            time_of_collection: frappe.datetime.now_time(),
                            milker: '',
                            animal_product: p.name,
                            default_uom: p.default_unit_of_measure || '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── When animal changes ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="animal"]', function () {
                const animal = $(this).val();
                set_product_query_for_animal(animal);

                const tbl = dialog.fields_dict.production_table;
                const shed_tbl = dialog.fields_dict.shed_production_table;

                const is_cattle_animal = ['Cattle', 'Cow'].includes(animal);
                const is_animal_specific = dialog.get_value('is_animal_specific');

                dialog.set_value('cattle', '');
                dialog.set_value('cattle_shed', '');

                if (!animal) {
                    if (tbl) { tbl.df.data = []; if (tbl.grid) tbl.grid.refresh(); }
                    if (shed_tbl) { shed_tbl.df.data = []; if (shed_tbl.grid) shed_tbl.grid.refresh(); }
                    return;
                }

                if (is_animal_specific) {
                    if (is_cattle_animal) {
                        populate_rows_for_all_cattle();
                    } else {
                        populate_rows_from_products_for_animal(animal);
                    }
                } else {
                    populate_shed_rows_from_products(animal);
                }
            });

            // ───── When checkbox modes change, repopulate accordingly ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="is_animal_specific"], input[data-fieldname="is_shed_specific"]', function () {
                setTimeout(function () {
                    const animal = dialog.get_value('animal');
                    if (!animal) return;
                    const is_animal_specific = dialog.get_value('is_animal_specific');
                    const is_cattle_animal = ['Cattle', 'Cow'].includes(animal);

                    if (is_animal_specific) {
                        if (is_cattle_animal) {
                            populate_rows_for_all_cattle();
                        } else {
                            populate_rows_from_products_for_animal(animal);
                        }
                    } else {
                        populate_shed_rows_from_products(animal);
                    }
                }, 100);
            });

            // ───── If user selects a single cow in the top-level cattle field ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="cattle"]', function () {
                const selected_cow = $(this).val();
                const animal = dialog.get_value('animal');
                if (!selected_cow) return;
                if (!['Cattle', 'Cow'].includes(animal)) return;

                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Cattle', filters: { name: selected_cow }, fieldname: 'add_nickname_optional' },
                    callback: function (r) {
                        const nick = (r && r.message && r.message.add_nickname_optional) || '';
                        tbl.df.data = [{
                            cattle: selected_cow,
                            cattle_nickname: nick,
                            time_of_collection: frappe.datetime.now_time(),
                            milker: '',
                            animal_product: '',
                            default_uom: '',
                            quantity_collected: 0.0
                        }];
                        if (tbl.grid) tbl.grid.refresh();

                        const grid = tbl.grid;
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows[0];
                                if (gr && gr.fields_map && gr.fields_map.cattle) {
                                    gr.fields_map.cattle.df.read_only = 1;
                                    gr.fields_map.cattle.$input && gr.fields_map.cattle.$input.prop('readonly', true);
                                    gr.toggle_remove_button && gr.toggle_remove_button(false);
                                }
                                if (gr && gr.fields_map && gr.fields_map.cattle_nickname) {
                                    gr.fields_map.cattle_nickname.df.read_only = 1;
                                    gr.fields_map.cattle_nickname.$input && gr.fields_map.cattle_nickname.$input.prop('readonly', true);
                                }
                            }
                            dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                        } catch (e) { console.warn('Could not lock single-cow row', e); }

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch cow nickname'), indicator: 'red' }, 10);
                    }
                });
            });

            // ───── When a cattle_shed is selected in the shed table OR top-level, auto-fill shed_info ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="cattle_shed"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;

                // Check if this is the top-level shed field
                const $row = $input.closest('.grid-row');
                if (!$row.length) {
                    // Top-level cattle_shed selected — populate shed table with that shed
                    const tbl = dialog.fields_dict.shed_production_table;
                    if (!tbl) return;
                    frappe.call({
                        method: 'frappe.client.get_value',
                        args: { doctype: 'Cattle Shed', filters: { name: val }, fieldname: ['shed_description', 'current_animal_count'] },
                        callback: function (r) {
                            const desc = (r && r.message && r.message.shed_description) || '';
                            const count = (r && r.message && r.message.current_animal_count) || '';
                            const info = desc + ' (' + count + ')';

                            // Get current animal for products
                            const animal = dialog.get_value('animal');
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Animal Products',
                                    filters: { product_tied_to_which_animal: animal },
                                    fields: ['name', 'default_unit_of_measure'],
                                    limit_page_length: 500
                                },
                                callback: function (pr) {
                                    if (!pr.message || !pr.message.length) {
                                        tbl.df.data = [{ cattle_shed: val, shed_info: info, time_of_collection: frappe.datetime.now_time(), milker: '', animal_product: '', default_uom: '', quantity_collected: 0.0 }];
                                        if (tbl.grid) tbl.grid.refresh();
                                        return;
                                    }
                                    const rows = pr.message.map(p => ({
                                        cattle_shed: val,
                                        shed_info: info,
                                        time_of_collection: frappe.datetime.now_time(),
                                        milker: '',
                                        animal_product: p.name,
                                        default_uom: p.default_unit_of_measure || '',
                                        quantity_collected: 0.0
                                    }));
                                    tbl.df.data = rows;
                                    if (tbl.grid) tbl.grid.refresh();
                                    set_product_query_for_animal(animal);
                                }
                            });
                        }
                    });
                    return;
                }

                // In-table cattle_shed change — fill shed_info for that row
                const rowName = $row.attr('data-name');
                const tbl = dialog.fields_dict.shed_production_table;
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Cattle Shed', filters: { name: val }, fieldname: ['shed_description', 'current_animal_count'] },
                    callback: function (r) {
                        const desc = (r && r.message && r.message.shed_description) || '';
                        const count = (r && r.message && r.message.current_animal_count) || '';
                        const info = desc + ' (' + count + ')';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.shed_info = info;
                                    if (gr.refresh_field) gr.refresh_field('shed_info');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set shed_info failed', e); }
                    }
                });
            });

            // ───── When an animal_product link is selected, auto-fill default_uom for that row ─────
            dialog.$wrapper.on('awesomplete-selectcomplete', 'input[data-fieldname="animal_product"]', function () {
                const $input = $(this);
                const val = $input.val();
                const $row = $input.closest('.grid-row');
                const rowName = $row.attr('data-name');

                // Determine which table this belongs to
                const is_shed_mode = dialog.get_value('is_shed_specific');
                const tbl = is_shed_mode ? dialog.fields_dict.shed_production_table : dialog.fields_dict.production_table;
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Animal Products', filters: { name: val }, fieldname: 'default_unit_of_measure' },
                    callback: function (r) {
                        const uom = (r && r.message && r.message.default_unit_of_measure) || '';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.default_uom = uom;
                                    if (gr.refresh_field) gr.refresh_field('default_uom');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set default_uom failed', e); }
                    }
                });
            });

            // ───── Newly added rows pick up the query for current animal ─────
            dialog.$wrapper.on('click', '.grid-add-row, .grid-add-rows, .grid-row-add', function () {
                setTimeout(function () {
                    const animal_val = dialog.get_value('animal');
                    set_product_query_for_animal(animal_val);
                }, 50);
            });

            // ───── Prevent future date on blur ─────
            dialog.$wrapper.on('blur', 'input[data-fieldname="date_of_collection"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;
                const today = frappe.datetime.get_today();
                if (val > today) {
                    frappe.show_alert({ message: __('Date of Collection cannot be a future date. The value has been reset to today.'), indicator: 'orange' }, 5);
                    dialog.set_value('date_of_collection', today);
                    $input.val(today);
                    try { $input.blur(); } catch (e) { }
                }
            });

            // ───── Initialize default queries for initial animal value ─────
            set_product_query_for_animal(dialog.get_value('animal'));
            const initial_animal = dialog.get_value('animal');
            if (['Cattle', 'Cow'].includes(initial_animal)) {
                populate_rows_for_all_cattle();
            } else if (initial_animal) {
                populate_rows_from_products_for_animal(initial_animal);
            }

        }).addClass('btn-primary');

        // ═══════════════════════════════════════════════════════════════════════
        // ──────── "Cull Animal?" Button ────────
        // ═══════════════════════════════════════════════════════════════════════
        list_view.page.add_inner_button(__('Cull Animal?'), () => {
            const today = frappe.datetime.get_today();

            // Fetch all active Cattle (not culled)
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Cattle',
                    filters: { has_been_culled: 0 },
                    fields: ['name', 'add_nickname_optional', 'cow_shed'],
                    limit_page_length: 2000
                },
                callback: function (r) {
                    const all_animals = (r && r.message) || [];
                    if (!all_animals.length) {
                        frappe.msgprint(__("No active Cattle found to cull."));
                        return;
                    }

                    // Build initial HTML table
                    function build_animal_table(animals) {
                        if (!animals.length) {
                            return '<p class="text-muted">' + __("No animals match the current filters.") + '</p>';
                        }
                        let html = '<table class="table table-bordered table-hover" style="margin-top:10px;">';
                        html += '<thead><tr>';
                        html += '<th style="width:40px;"><input type="checkbox" class="cull-select-all"></th>';
                        html += '<th>' + __("Animal ID") + '</th>';
                        html += '<th>' + __("Nickname") + '</th>';
                        html += '<th>' + __("Shed") + '</th>';
                        html += '</tr></thead><tbody>';
                        animals.forEach(a => {
                            html += '<tr>';
                            html += '<td><input type="checkbox" class="cull-animal-check" data-animal="' + a.name + '"></td>';
                            html += '<td>' + a.name + '</td>';
                            html += '<td>' + (a.add_nickname_optional || '-') + '</td>';
                            html += '<td>' + (a.cow_shed || '-') + '</td>';
                            html += '</tr>';
                        });
                        html += '</tbody></table>';
                        return html;
                    }

                    const cull_dialog = new frappe.ui.Dialog({
                        title: __("Cull Animal"),
                        fields: [
                            {
                                fieldtype: 'Date',
                                fieldname: 'date_of_cull',
                                label: __('Date of Cull'),
                                default: today,
                                reqd: 1
                            },
                            { fieldtype: 'Column Break' },
                            {
                                fieldtype: 'Link',
                                fieldname: 'filter_shed',
                                label: __('Filter by Shed'),
                                options: 'Cattle Shed'
                            },
                            {
                                fieldtype: 'Link',
                                fieldname: 'filter_animal',
                                label: __('Filter by Specific Animal'),
                                options: 'Cattle',
                                get_query: function () {
                                    return { filters: { has_been_culled: 0 } };
                                }
                            },
                            { fieldtype: 'Section Break' },
                            {
                                fieldtype: 'HTML',
                                fieldname: 'animal_list_html',
                                label: __('Select Animals to Cull')
                            }
                        ],
                        size: 'large',
                        primary_action_label: __('Cull Selected'),
                        primary_action: function () {
                            const checked = cull_dialog.$wrapper.find('.cull-animal-check:checked');
                            if (!checked.length) {
                                frappe.msgprint(__("Please select at least one animal to cull."));
                                return;
                            }

                            const selected_animals = [];
                            checked.each(function () {
                                selected_animals.push($(this).data('animal'));
                            });

                            const date_val = cull_dialog.get_value('date_of_cull');

                            // ── Confirmation ──
                            frappe.confirm(
                                __("You are about to cull {0} animal(s). This action is IRREVERSIBLE and will also scrap any linked Assets. Are you sure?", [selected_animals.length]),
                                () => {
                                    frappe.call({
                                        method: 'farm_management_system.savanna_farm_suite.doctype.cattle.cattle.cull_animal',
                                        args: {
                                            animals: JSON.stringify(selected_animals),
                                            date_of_cull: date_val
                                        },
                                        freeze: true,
                                        freeze_message: __("Culling animals…"),
                                        callback: function (resp) {
                                            if (resp && !resp.exc) {
                                                try {
                                                    var audio = new Audio('/assets/farm_management_system/sounds/success.mp3');
                                                    audio.play();
                                                } catch (e) { }
                                                frappe.show_alert({ message: __("{0} animal(s) culled successfully", [selected_animals.length]), indicator: 'green' }, 5);
                                                cull_dialog.hide();
                                                list_view.refresh();
                                            } else {
                                                try {
                                                    var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                                    errAudio.play();
                                                } catch (e) { }
                                            }
                                        },
                                        error: function () {
                                            try {
                                                var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                                errAudio.play();
                                            } catch (e) { }
                                        }
                                    });
                                }
                            );
                        }
                    });

                    cull_dialog.show();
                    cull_dialog.$wrapper.find('.modal-dialog').css('max-width', '800px');

                    // Render initial table
                    const html_field = cull_dialog.fields_dict.animal_list_html;
                    html_field.$wrapper.html(build_animal_table(all_animals));

                    // Select-all checkbox
                    html_field.$wrapper.on('change', '.cull-select-all', function () {
                        const is_checked = $(this).prop('checked');
                        html_field.$wrapper.find('.cull-animal-check').prop('checked', is_checked);
                    });

                    // Filter logic
                    function apply_filters() {
                        const shed_val = cull_dialog.get_value('filter_shed');
                        const animal_val = cull_dialog.get_value('filter_animal');

                        let filtered = all_animals;
                        if (shed_val) {
                            filtered = filtered.filter(a => a.cow_shed === shed_val);
                        }
                        if (animal_val) {
                            filtered = filtered.filter(a => a.name === animal_val);
                        }
                        html_field.$wrapper.html(build_animal_table(filtered));
                    }

                    cull_dialog.fields_dict.filter_shed.df.onchange = apply_filters;
                    cull_dialog.fields_dict.filter_animal.df.onchange = apply_filters;
                }
            });
        });
    }
};

// farm_management_system/savanna_farm_suite/doctype/goat/goat_list.js
frappe.listview_settings['Goat'] = {
    refresh: function (list_view) {
        list_view.page.add_inner_button(__('Make Collection'), () => {
            const dialog = new frappe.ui.Dialog({
                title: __('Make a Collection of Animal Products'),
                fields: [
                    { fieldtype: 'Date', fieldname: 'date_of_collection', label: __('Date of Collection'), default: frappe.datetime.get_today(), reqd: 1 },
                    { fieldtype: 'Link', fieldname: 'animal', label: __('Specify Animal'), options: 'Animals', default: "Goat", reqd: 1 },
                    { fieldtype: 'Check', fieldname: 'is_animal_specific', label: __('Is Animal Specific?'), default: 1 },
                    { fieldtype: 'Check', fieldname: 'is_shed_specific', label: __('Is Shed Specific?'), default: 0 },
                    { fieldtype: 'Link', fieldname: 'goat', label: __('Specify Goat'), options: 'Goat', description: __('NOTE: Only Use for a single Goat if Applicable.'), depends_on: 'eval:doc.is_animal_specific==1' },
                    { fieldtype: 'Link', fieldname: 'goat_shed', label: __('Specify Goat Shed'), options: 'Goat Shed', description: __('Select a shed to collect for ALL goat in it.'), depends_on: 'eval:doc.is_shed_specific==1' },
                    {
                        fieldtype: 'Table',
                        fieldname: 'production_table',
                        label: __('Collections Table'),
                        description: __('Use this table for <b>Multiple Entries</b>'),
                        depends_on: 'eval:doc.is_animal_specific==1',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'goat', label: __('Goat'), options: 'Goat', in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'goat_nickname', label: __('Nickname'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'default_uom', label: __('Default UOM'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_collected', label: __('Quantity Collected'), reqd: 1, in_list_view: 1 }
                        ]
                    },
                    {
                        fieldtype: 'Table',
                        fieldname: 'shed_production_table',
                        label: __('Shed Collections Table'),
                        description: __('Use this table for <b>Shed-based Entries</b>'),
                        depends_on: 'eval:doc.is_shed_specific==1',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'goat_shed', label: __('Goat Shed'), options: 'Goat Shed', in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'shed_info', label: __('Shed Info'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'default_uom', label: __('Default UOM'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_collected', label: __('Quantity Collected'), reqd: 1, in_list_view: 1 }
                        ]
                    }
                ],
                primary_action_label: __('Make Entry'),
                primary_action: function () {
                    const dvalues = dialog.get_values(true);
                    const today = frappe.datetime.get_today();
                    const selected_date = dvalues && dvalues.date_of_collection;
                    if (selected_date && selected_date > today) {
                        frappe.show_alert({ message: __('Date of Collection cannot be a future date.'), indicator: 'orange' }, 5);
                        return;
                    }

                    const is_shed = dvalues.is_shed_specific;
                    const rows = is_shed ? (dvalues.shed_production_table || []) : (dvalues.production_table || []);
                    if (!rows.length) {
                        frappe.show_alert({ message: __('No products found to collect.'), indicator: 'orange' }, 5);
                        return;
                    }

                    frappe.warn(
                        __('Are you sure you want to proceed?'),
                        __('Please Note this Action is Irreversible'),
                        () => {
                            frappe.dom.freeze(__('Creating collection...'));
                            frappe.call({
                                method: 'farm_management_system.savanna_farm_suite.doctype.goat.goat.create_collection_entry',
                                args: {
                                    goat: is_shed ? null : (dvalues.goat || null),
                                    date_of_collection: dvalues.date_of_collection,
                                    rows: rows
                                },
                                callback: function (r) {
                                    frappe.dom.unfreeze();
                                    if (!r.exc && r.message) {
                                        // Play custom success sound
                                        var audio = new Audio('/assets/farm_management_system/sounds/success.mp3');
                                        audio.play().catch(function () { frappe.utils.play_sound('submit'); });
                                        dialog.hide();
                                        list_view.refresh();
                                        frappe.show_alert({ message: __('Collection recorded'), indicator: 'green' }, 5);
                                    } else if (r.exc) {
                                        // Play custom error sound
                                        var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                        errAudio.play().catch(function () { });
                                        const errMsg = (typeof r.exc === 'string') ? r.exc : (r._server_messages || r.exc || __('Unknown error occurred'));
                                        frappe.show_alert({ message: __('Error: ') + errMsg, indicator: 'red' }, 10);
                                    }
                                },
                                error: function () {
                                    frappe.dom.unfreeze();
                                    // Play custom error sound
                                    var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                    errAudio.play().catch(function () { });
                                    frappe.show_alert({ message: __('Network Error: Please try again.'), indicator: 'red' }, 10);
                                }
                            });
                        },
                        'Continue',
                        true
                    );
                }
            });

            dialog.show();
            dialog.$wrapper.find('.modal-dialog').addClass('modal-lg');

            // ───── Mutual exclusion for checkboxes ─────
            dialog.fields_dict.is_animal_specific.$input.on('change', function () {
                if (dialog.get_value('is_animal_specific')) {
                    dialog.set_value('is_shed_specific', 0);
                }
            });
            dialog.fields_dict.is_shed_specific.$input.on('change', function () {
                if (dialog.get_value('is_shed_specific')) {
                    dialog.set_value('is_animal_specific', 0);
                }
            });

            // ───── Helper: apply per-row + top-level query so animal_product only shows products for selected animal ─────
            function set_product_query_for_animal(animal_name) {
                const get_query_fn = function () {
                    if (!animal_name) return { filters: {} };
                    return { filters: { product_tied_to_which_animal: animal_name } };
                };

                // Apply to animal-specific table
                _apply_product_query_to_table(dialog.fields_dict.production_table, get_query_fn);
                // Apply to shed-specific table
                _apply_product_query_to_table(dialog.fields_dict.shed_production_table, get_query_fn);
            }

            function _apply_product_query_to_table(tbl, get_query_fn) {
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                try {
                    if (typeof grid.get_field === 'function') {
                        const topField = grid.get_field('animal_product');
                        if (topField) {
                            topField.get_query = get_query_fn;
                            if (topField.df) topField.df.get_query = get_query_fn;
                        }
                    }
                } catch (e) { console.warn('set_product_query top set failed', e); }

                try {
                    (grid.grid_rows || []).forEach(function (gr) {
                        try {
                            const f = gr.fields_map && gr.fields_map.animal_product;
                            if (f) {
                                f.get_query = get_query_fn;
                                if (f.df) f.df.get_query = get_query_fn;
                                if (gr.doc && gr.doc.animal_product) {
                                    gr.doc.animal_product = '';
                                    if (gr.refresh_field) gr.refresh_field('animal_product');
                                }
                            }
                        } catch (inner) { /* ignore per-row errors */ }
                    });
                } catch (e) { console.warn('set_product_query per-row set failed', e); }

                try { grid.refresh(); } catch (e) { }
            }

            // ───── Helper: populate rows for all active goat (has_been_culled == 0) ─────
            function populate_rows_for_all_goat() {
                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Goat',
                        filters: { has_been_culled: 0 },
                        fields: ['name', 'add_nickname_optional'],
                        limit_page_length: 2000
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (tbl.grid) tbl.grid.refresh();
                            frappe.show_alert({ message: __('No active Goat found'), indicator: 'orange' }, 5);
                            return;
                        }

                        const rows = r.message.map(c => ({
                            goat: c.name,
                            goat_nickname: c.add_nickname_optional || '',
                            animal_product: '',
                            default_uom: '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                grid.grid_rows.forEach(function (gr) {
                                    try {
                                        if (gr.fields_map && gr.fields_map.goat) {
                                            gr.fields_map.goat.df.read_only = 1;
                                            gr.fields_map.goat.$input && gr.fields_map.goat.$input.prop('readonly', true);
                                        }
                                        if (gr.fields_map && gr.fields_map.goat_nickname) {
                                            gr.fields_map.goat_nickname.df.read_only = 1;
                                            gr.fields_map.goat_nickname.$input && gr.fields_map.goat_nickname.$input.prop('readonly', true);
                                        }
                                        gr.toggle_remove_button && gr.toggle_remove_button(false);
                                    } catch (e) { }
                                });
                            }
                            dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                        } catch (e) {
                            console.warn('Could not lock child rows after goat populate', e);
                        }

                        set_product_query_for_animal(dialog.get_value('animal'));
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Goat'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── Helper: populate rows from list of Animal Products (one row per product) ─────
            function populate_rows_from_products_for_animal(animal) {
                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Animal Products',
                        filters: { product_tied_to_which_animal: animal },
                        fields: ['name', 'default_unit_of_measure'],
                        limit_page_length: 500
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (grid) grid.refresh();
                            frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' }, 5);
                            return;
                        }

                        const products = r.message;
                        const rows = products.map(p => ({
                            goat: '',
                            goat_nickname: '',
                            animal_product: p.name,
                            default_uom: p.default_unit_of_measure || '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').show();
                        if (grid.grid_rows && grid.grid_rows.length) {
                            grid.grid_rows.forEach(function (gr) {
                                try {
                                    if (gr.fields_map && gr.fields_map.goat) {
                                        gr.fields_map.goat.df.read_only = 0;
                                        gr.fields_map.goat.$input && gr.fields_map.goat.$input.prop('readonly', false);
                                        gr.toggle_remove_button && gr.toggle_remove_button(true);
                                    }
                                    if (gr.fields_map && gr.fields_map.goat_nickname) {
                                        gr.fields_map.goat_nickname.df.read_only = 1;
                                        gr.fields_map.goat_nickname.$input && gr.fields_map.goat_nickname.$input.prop('readonly', true);
                                    }
                                } catch (e) { }
                            });
                        }

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── Helper: populate shed table rows from products ─────
            function populate_shed_rows_from_products(animal) {
                const tbl = dialog.fields_dict.shed_production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Animal Products',
                        filters: { product_tied_to_which_animal: animal },
                        fields: ['name', 'default_unit_of_measure'],
                        limit_page_length: 500
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (grid) grid.refresh();
                            frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' }, 5);
                            return;
                        }

                        const products = r.message;
                        const rows = products.map(p => ({
                            goat_shed: '',
                            shed_info: '',
                            animal_product: p.name,
                            default_uom: p.default_unit_of_measure || '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── When animal changes ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="animal"]', function () {
                const animal = $(this).val();
                set_product_query_for_animal(animal);

                const tbl = dialog.fields_dict.production_table;
                const shed_tbl = dialog.fields_dict.shed_production_table;

                const is_goat_animal = ['Goat'].includes(animal);
                const is_animal_specific = dialog.get_value('is_animal_specific');

                dialog.set_value('goat', '');
                dialog.set_value('goat_shed', '');

                if (!animal) {
                    if (tbl) { tbl.df.data = []; if (tbl.grid) tbl.grid.refresh(); }
                    if (shed_tbl) { shed_tbl.df.data = []; if (shed_tbl.grid) shed_tbl.grid.refresh(); }
                    return;
                }

                if (is_animal_specific) {
                    if (is_goat_animal) {
                        populate_rows_for_all_goat();
                    } else {
                        populate_rows_from_products_for_animal(animal);
                    }
                } else {
                    populate_shed_rows_from_products(animal);
                }
            });

            // ───── When checkbox modes change, repopulate accordingly ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="is_animal_specific"], input[data-fieldname="is_shed_specific"]', function () {
                setTimeout(function () {
                    const animal = dialog.get_value('animal');
                    if (!animal) return;
                    const is_animal_specific = dialog.get_value('is_animal_specific');
                    const is_goat_animal = ['Goat'].includes(animal);

                    if (is_animal_specific) {
                        if (is_goat_animal) {
                            populate_rows_for_all_goat();
                        } else {
                            populate_rows_from_products_for_animal(animal);
                        }
                    } else {
                        populate_shed_rows_from_products(animal);
                    }
                }, 100);
            });

            // ───── If user selects a single goat in the top-level goat field ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="goat"]', function () {
                const selected_goat = $(this).val();
                const animal = dialog.get_value('animal');
                if (!selected_goat) return;
                if (!['Goat'].includes(animal)) return;

                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Goat', filters: { name: selected_goat }, fieldname: 'add_nickname_optional' },
                    callback: function (r) {
                        const nick = (r && r.message && r.message.add_nickname_optional) || '';
                        tbl.df.data = [{
                            goat: selected_goat,
                            goat_nickname: nick,
                            animal_product: '',
                            default_uom: '',
                            quantity_collected: 0.0
                        }];
                        if (tbl.grid) tbl.grid.refresh();

                        const grid = tbl.grid;
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows[0];
                                if (gr && gr.fields_map && gr.fields_map.goat) {
                                    gr.fields_map.goat.df.read_only = 1;
                                    gr.fields_map.goat.$input && gr.fields_map.goat.$input.prop('readonly', true);
                                    gr.toggle_remove_button && gr.toggle_remove_button(false);
                                }
                                if (gr && gr.fields_map && gr.fields_map.goat_nickname) {
                                    gr.fields_map.goat_nickname.df.read_only = 1;
                                    gr.fields_map.goat_nickname.$input && gr.fields_map.goat_nickname.$input.prop('readonly', true);
                                }
                            }
                            dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                        } catch (e) { console.warn('Could not lock single-goat row', e); }

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch goat nickname'), indicator: 'red' }, 10);
                    }
                });
            });

            // ───── When a goat_shed is selected in the shed table OR top-level, auto-fill shed_info ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="goat_shed"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;

                // Check if this is the top-level shed field
                const $row = $input.closest('.grid-row');
                if (!$row.length) {
                    // Top-level goat_shed selected — populate shed table with that shed
                    const tbl = dialog.fields_dict.shed_production_table;
                    if (!tbl) return;
                    frappe.call({
                        method: 'frappe.client.get_value',
                        args: { doctype: 'Goat Shed', filters: { name: val }, fieldname: ['shed_description', 'current_animal_count'] },
                        callback: function (r) {
                            const desc = (r && r.message && r.message.shed_description) || '';
                            const count = (r && r.message && r.message.current_animal_count) || '';
                            const info = desc + ' (' + count + ')';

                            // Get current animal for products
                            const animal = dialog.get_value('animal');
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Animal Products',
                                    filters: { product_tied_to_which_animal: animal },
                                    fields: ['name', 'default_unit_of_measure'],
                                    limit_page_length: 500
                                },
                                callback: function (pr) {
                                    if (!pr.message || !pr.message.length) {
                                        tbl.df.data = [{ goat_shed: val, shed_info: info, animal_product: '', default_uom: '', quantity_collected: 0.0 }];
                                        if (tbl.grid) tbl.grid.refresh();
                                        return;
                                    }
                                    const rows = pr.message.map(p => ({
                                        goat_shed: val,
                                        shed_info: info,
                                        animal_product: p.name,
                                        default_uom: p.default_unit_of_measure || '',
                                        quantity_collected: 0.0
                                    }));
                                    tbl.df.data = rows;
                                    if (tbl.grid) tbl.grid.refresh();
                                    set_product_query_for_animal(animal);
                                }
                            });
                        }
                    });
                    return;
                }

                // In-table goat_shed change — fill shed_info for that row
                const rowName = $row.attr('data-name');
                const tbl = dialog.fields_dict.shed_production_table;
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Goat Shed', filters: { name: val }, fieldname: ['shed_description', 'current_animal_count'] },
                    callback: function (r) {
                        const desc = (r && r.message && r.message.shed_description) || '';
                        const count = (r && r.message && r.message.current_animal_count) || '';
                        const info = desc + ' (' + count + ')';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.shed_info = info;
                                    if (gr.refresh_field) gr.refresh_field('shed_info');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set shed_info failed', e); }
                    }
                });
            });

            // ───── When an animal_product link is selected, auto-fill default_uom for that row ─────
            dialog.$wrapper.on('awesomplete-selectcomplete', 'input[data-fieldname="animal_product"]', function () {
                const $input = $(this);
                const val = $input.val();
                const $row = $input.closest('.grid-row');
                const rowName = $row.attr('data-name');

                // Determine which table this belongs to
                const is_shed_mode = dialog.get_value('is_shed_specific');
                const tbl = is_shed_mode ? dialog.fields_dict.shed_production_table : dialog.fields_dict.production_table;
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Animal Products', filters: { name: val }, fieldname: 'default_unit_of_measure' },
                    callback: function (r) {
                        const uom = (r && r.message && r.message.default_unit_of_measure) || '';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.default_uom = uom;
                                    if (gr.refresh_field) gr.refresh_field('default_uom');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set default_uom failed', e); }
                    }
                });
            });

            // ───── Newly added rows pick up the query for current animal ─────
            dialog.$wrapper.on('click', '.grid-add-row, .grid-add-rows, .grid-row-add', function () {
                setTimeout(function () {
                    const animal_val = dialog.get_value('animal');
                    set_product_query_for_animal(animal_val);
                }, 50);
            });

            // ───── Prevent future date on blur ─────
            dialog.$wrapper.on('blur', 'input[data-fieldname="date_of_collection"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;
                const today = frappe.datetime.get_today();
                if (val > today) {
                    frappe.show_alert({ message: __('Date of Collection cannot be a future date. The value has been reset to today.'), indicator: 'orange' }, 5);
                    dialog.set_value('date_of_collection', today);
                    $input.val(today);
                    try { $input.blur(); } catch (e) { }
                }
            });

            // ───── Initialize default queries for initial animal value ─────
            set_product_query_for_animal(dialog.get_value('animal'));
            const initial_animal = dialog.get_value('animal');
            if (['Goat'].includes(initial_animal)) {
                populate_rows_for_all_goat();
            } else if (initial_animal) {
                populate_rows_from_products_for_animal(initial_animal);
            }

        }).addClass('btn-primary');

        // ═══════════════════════════════════════════════════════════════════════
        // ──────── "Cull Animal?" Button ────────
        // ═══════════════════════════════════════════════════════════════════════
        list_view.page.add_inner_button(__('Cull Animal?'), () => {
            const today = frappe.datetime.get_today();

            // Fetch all active Goat (not culled)
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Goat',
                    filters: { has_been_culled: 0 },
                    fields: ['name', 'add_nickname_optional', 'goat_shed'],
                    limit_page_length: 2000
                },
                callback: function (r) {
                    const all_animals = (r && r.message) || [];
                    if (!all_animals.length) {
                        frappe.msgprint(__("No active Goat found to cull."));
                        return;
                    }

                    // Build initial HTML table
                    function build_animal_table(animals) {
                        if (!animals.length) {
                            return '<p class="text-muted">' + __("No animals match the current filters.") + '</p>';
                        }
                        let html = '<table class="table table-bordered table-hover" style="margin-top:10px;">';
                        html += '<thead><tr>';
                        html += '<th style="width:40px;"><input type="checkbox" class="cull-select-all"></th>';
                        html += '<th>' + __("Animal ID") + '</th>';
                        html += '<th>' + __("Nickname") + '</th>';
                        html += '<th>' + __("Shed") + '</th>';
                        html += '</tr></thead><tbody>';
                        animals.forEach(a => {
                            html += '<tr>';
                            html += '<td><input type="checkbox" class="cull-animal-check" data-animal="' + a.name + '"></td>';
                            html += '<td>' + a.name + '</td>';
                            html += '<td>' + (a.add_nickname_optional || '-') + '</td>';
                            html += '<td>' + (a.goat_shed || '-') + '</td>';
                            html += '</tr>';
                        });
                        html += '</tbody></table>';
                        return html;
                    }

                    const cull_dialog = new frappe.ui.Dialog({
                        title: __("Cull Animal"),
                        fields: [
                            {
                                fieldtype: 'Date',
                                fieldname: 'date_of_cull',
                                label: __('Date of Cull'),
                                default: today,
                                reqd: 1
                            },
                            { fieldtype: 'Column Break' },
                            {
                                fieldtype: 'Link',
                                fieldname: 'filter_shed',
                                label: __('Filter by Shed'),
                                options: 'Goat Shed'
                            },
                            {
                                fieldtype: 'Link',
                                fieldname: 'filter_animal',
                                label: __('Filter by Specific Animal'),
                                options: 'Goat',
                                get_query: function () {
                                    return { filters: { has_been_culled: 0 } };
                                }
                            },
                            { fieldtype: 'Section Break' },
                            {
                                fieldtype: 'HTML',
                                fieldname: 'animal_list_html',
                                label: __('Select Animals to Cull')
                            }
                        ],
                        size: 'large',
                        primary_action_label: __('Cull Selected'),
                        primary_action: function () {
                            const checked = cull_dialog.$wrapper.find('.cull-animal-check:checked');
                            if (!checked.length) {
                                frappe.msgprint(__("Please select at least one animal to cull."));
                                return;
                            }

                            const selected_animals = [];
                            checked.each(function () {
                                selected_animals.push($(this).data('animal'));
                            });

                            const date_val = cull_dialog.get_value('date_of_cull');

                            // ── Confirmation ──
                            frappe.confirm(
                                __("You are about to cull {0} animal(s). This action is IRREVERSIBLE and will also scrap any linked Assets. Are you sure?", [selected_animals.length]),
                                () => {
                                    frappe.call({
                                        method: 'farm_management_system.savanna_farm_suite.doctype.goat.goat.cull_animal',
                                        args: {
                                            animals: JSON.stringify(selected_animals),
                                            date_of_cull: date_val
                                        },
                                        freeze: true,
                                        freeze_message: __("Culling animals…"),
                                        callback: function (resp) {
                                            if (resp && !resp.exc) {
                                                try {
                                                    var audio = new Audio('/assets/farm_management_system/sounds/success.mp3');
                                                    audio.play();
                                                } catch (e) { }
                                                frappe.show_alert({ message: __("{0} animal(s) culled successfully", [selected_animals.length]), indicator: 'green' }, 5);
                                                cull_dialog.hide();
                                                list_view.refresh();
                                            } else {
                                                try {
                                                    var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                                    errAudio.play();
                                                } catch (e) { }
                                            }
                                        },
                                        error: function () {
                                            try {
                                                var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                                errAudio.play();
                                            } catch (e) { }
                                        }
                                    });
                                }
                            );
                        }
                    });

                    cull_dialog.show();
                    cull_dialog.$wrapper.find('.modal-dialog').css('max-width', '800px');

                    // Render initial table
                    const html_field = cull_dialog.fields_dict.animal_list_html;
                    html_field.$wrapper.html(build_animal_table(all_animals));

                    // Select-all checkbox
                    html_field.$wrapper.on('change', '.cull-select-all', function () {
                        const is_checked = $(this).prop('checked');
                        html_field.$wrapper.find('.cull-animal-check').prop('checked', is_checked);
                    });

                    // Filter logic
                    function apply_filters() {
                        const shed_val = cull_dialog.get_value('filter_shed');
                        const animal_val = cull_dialog.get_value('filter_animal');

                        let filtered = all_animals;
                        if (shed_val) {
                            filtered = filtered.filter(a => a.goat_shed === shed_val);
                        }
                        if (animal_val) {
                            filtered = filtered.filter(a => a.name === animal_val);
                        }
                        html_field.$wrapper.html(build_animal_table(filtered));
                    }

                    cull_dialog.fields_dict.filter_shed.df.onchange = apply_filters;
                    cull_dialog.fields_dict.filter_animal.df.onchange = apply_filters;
                }
            });
        });
    }
};

// farm_management_system/savanna_farm_suite/doctype/pig/pig_list.js
frappe.listview_settings['Pig'] = {
    refresh: function (list_view) {
        list_view.page.add_inner_button(__('Make Collection'), () => {
            const dialog = new frappe.ui.Dialog({
                title: __('Make a Collection of Animal Products'),
                fields: [
                    { fieldtype: 'Date', fieldname: 'date_of_collection', label: __('Date of Collection'), default: frappe.datetime.get_today(), reqd: 1 },
                    { fieldtype: 'Link', fieldname: 'animal', label: __('Specify Animal'), options: 'Animals', default: "Pig", reqd: 1 },
                    { fieldtype: 'Check', fieldname: 'is_animal_specific', label: __('Is Animal Specific?'), default: 1 },
                    { fieldtype: 'Check', fieldname: 'is_shed_specific', label: __('Is Shed Specific?'), default: 0 },
                    { fieldtype: 'Link', fieldname: 'pig', label: __('Specify Pig'), options: 'Pig', description: __('NOTE: Only Use for a single Pig if Applicable.'), depends_on: 'eval:doc.is_animal_specific==1' },
                    { fieldtype: 'Link', fieldname: 'pig_shed', label: __('Specify Pig Shed'), options: 'Pig Shed', description: __('Select a shed to collect for ALL pig in it.'), depends_on: 'eval:doc.is_shed_specific==1' },
                    {
                        fieldtype: 'Table',
                        fieldname: 'production_table',
                        label: __('Collections Table'),
                        description: __('Use this table for <b>Multiple Entries</b>'),
                        depends_on: 'eval:doc.is_animal_specific==1',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'pig', label: __('Pig'), options: 'Pig', in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'pig_nickname', label: __('Nickname'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'default_uom', label: __('Default UOM'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_collected', label: __('Quantity Collected'), reqd: 1, in_list_view: 1 }
                        ]
                    },
                    {
                        fieldtype: 'Table',
                        fieldname: 'shed_production_table',
                        label: __('Shed Collections Table'),
                        description: __('Use this table for <b>Shed-based Entries</b>'),
                        depends_on: 'eval:doc.is_shed_specific==1',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'pig_shed', label: __('Pig Shed'), options: 'Pig Shed', in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'shed_info', label: __('Shed Info'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'default_uom', label: __('Default UOM'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_collected', label: __('Quantity Collected'), reqd: 1, in_list_view: 1 }
                        ]
                    }
                ],
                primary_action_label: __('Make Entry'),
                primary_action: function () {
                    const dvalues = dialog.get_values(true);
                    const today = frappe.datetime.get_today();
                    const selected_date = dvalues && dvalues.date_of_collection;
                    if (selected_date && selected_date > today) {
                        frappe.show_alert({ message: __('Date of Collection cannot be a future date.'), indicator: 'orange' }, 5);
                        return;
                    }

                    const is_shed = dvalues.is_shed_specific;
                    const rows = is_shed ? (dvalues.shed_production_table || []) : (dvalues.production_table || []);
                    if (!rows.length) {
                        frappe.show_alert({ message: __('No products found to collect.'), indicator: 'orange' }, 5);
                        return;
                    }

                    frappe.warn(
                        __('Are you sure you want to proceed?'),
                        __('Please Note this Action is Irreversible'),
                        () => {
                            frappe.dom.freeze(__('Creating collection...'));
                            frappe.call({
                                method: 'farm_management_system.savanna_farm_suite.doctype.pig.pig.create_collection_entry',
                                args: {
                                    pig: is_shed ? null : (dvalues.pig || null),
                                    date_of_collection: dvalues.date_of_collection,
                                    rows: rows
                                },
                                callback: function (r) {
                                    frappe.dom.unfreeze();
                                    if (!r.exc && r.message) {
                                        // Play custom success sound
                                        var audio = new Audio('/assets/farm_management_system/sounds/success.mp3');
                                        audio.play().catch(function () { frappe.utils.play_sound('submit'); });
                                        dialog.hide();
                                        list_view.refresh();
                                        frappe.show_alert({ message: __('Collection recorded'), indicator: 'green' }, 5);
                                    } else if (r.exc) {
                                        // Play custom error sound
                                        var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                        errAudio.play().catch(function () { });
                                        const errMsg = (typeof r.exc === 'string') ? r.exc : (r._server_messages || r.exc || __('Unknown error occurred'));
                                        frappe.show_alert({ message: __('Error: ') + errMsg, indicator: 'red' }, 10);
                                    }
                                },
                                error: function () {
                                    frappe.dom.unfreeze();
                                    // Play custom error sound
                                    var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                    errAudio.play().catch(function () { });
                                    frappe.show_alert({ message: __('Network Error: Please try again.'), indicator: 'red' }, 10);
                                }
                            });
                        },
                        'Continue',
                        true
                    );
                }
            });

            dialog.show();
            dialog.$wrapper.find('.modal-dialog').addClass('modal-lg');

            // ───── Mutual exclusion for checkboxes ─────
            dialog.fields_dict.is_animal_specific.$input.on('change', function () {
                if (dialog.get_value('is_animal_specific')) {
                    dialog.set_value('is_shed_specific', 0);
                }
            });
            dialog.fields_dict.is_shed_specific.$input.on('change', function () {
                if (dialog.get_value('is_shed_specific')) {
                    dialog.set_value('is_animal_specific', 0);
                }
            });

            // ───── Helper: apply per-row + top-level query so animal_product only shows products for selected animal ─────
            function set_product_query_for_animal(animal_name) {
                const get_query_fn = function () {
                    if (!animal_name) return { filters: {} };
                    return { filters: { product_tied_to_which_animal: animal_name } };
                };

                // Apply to animal-specific table
                _apply_product_query_to_table(dialog.fields_dict.production_table, get_query_fn);
                // Apply to shed-specific table
                _apply_product_query_to_table(dialog.fields_dict.shed_production_table, get_query_fn);
            }

            function _apply_product_query_to_table(tbl, get_query_fn) {
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                try {
                    if (typeof grid.get_field === 'function') {
                        const topField = grid.get_field('animal_product');
                        if (topField) {
                            topField.get_query = get_query_fn;
                            if (topField.df) topField.df.get_query = get_query_fn;
                        }
                    }
                } catch (e) { console.warn('set_product_query top set failed', e); }

                try {
                    (grid.grid_rows || []).forEach(function (gr) {
                        try {
                            const f = gr.fields_map && gr.fields_map.animal_product;
                            if (f) {
                                f.get_query = get_query_fn;
                                if (f.df) f.df.get_query = get_query_fn;
                                if (gr.doc && gr.doc.animal_product) {
                                    gr.doc.animal_product = '';
                                    if (gr.refresh_field) gr.refresh_field('animal_product');
                                }
                            }
                        } catch (inner) { /* ignore per-row errors */ }
                    });
                } catch (e) { console.warn('set_product_query per-row set failed', e); }

                try { grid.refresh(); } catch (e) { }
            }

            // ───── Helper: populate rows for all active pig (has_been_culled == 0) ─────
            function populate_rows_for_all_pig() {
                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Pig',
                        filters: { has_been_culled: 0 },
                        fields: ['name', 'add_nickname_optional'],
                        limit_page_length: 2000
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (tbl.grid) tbl.grid.refresh();
                            frappe.show_alert({ message: __('No active Pig found'), indicator: 'orange' }, 5);
                            return;
                        }

                        const rows = r.message.map(c => ({
                            pig: c.name,
                            pig_nickname: c.add_nickname_optional || '',
                            animal_product: '',
                            default_uom: '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                grid.grid_rows.forEach(function (gr) {
                                    try {
                                        if (gr.fields_map && gr.fields_map.pig) {
                                            gr.fields_map.pig.df.read_only = 1;
                                            gr.fields_map.pig.$input && gr.fields_map.pig.$input.prop('readonly', true);
                                        }
                                        if (gr.fields_map && gr.fields_map.pig_nickname) {
                                            gr.fields_map.pig_nickname.df.read_only = 1;
                                            gr.fields_map.pig_nickname.$input && gr.fields_map.pig_nickname.$input.prop('readonly', true);
                                        }
                                        gr.toggle_remove_button && gr.toggle_remove_button(false);
                                    } catch (e) { }
                                });
                            }
                            dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                        } catch (e) {
                            console.warn('Could not lock child rows after pig populate', e);
                        }

                        set_product_query_for_animal(dialog.get_value('animal'));
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Pig'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── Helper: populate rows from list of Animal Products (one row per product) ─────
            function populate_rows_from_products_for_animal(animal) {
                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Animal Products',
                        filters: { product_tied_to_which_animal: animal },
                        fields: ['name', 'default_unit_of_measure'],
                        limit_page_length: 500
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (grid) grid.refresh();
                            frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' }, 5);
                            return;
                        }

                        const products = r.message;
                        const rows = products.map(p => ({
                            pig: '',
                            pig_nickname: '',
                            animal_product: p.name,
                            default_uom: p.default_unit_of_measure || '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').show();
                        if (grid.grid_rows && grid.grid_rows.length) {
                            grid.grid_rows.forEach(function (gr) {
                                try {
                                    if (gr.fields_map && gr.fields_map.pig) {
                                        gr.fields_map.pig.df.read_only = 0;
                                        gr.fields_map.pig.$input && gr.fields_map.pig.$input.prop('readonly', false);
                                        gr.toggle_remove_button && gr.toggle_remove_button(true);
                                    }
                                    if (gr.fields_map && gr.fields_map.pig_nickname) {
                                        gr.fields_map.pig_nickname.df.read_only = 1;
                                        gr.fields_map.pig_nickname.$input && gr.fields_map.pig_nickname.$input.prop('readonly', true);
                                    }
                                } catch (e) { }
                            });
                        }

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── Helper: populate shed table rows from products ─────
            function populate_shed_rows_from_products(animal) {
                const tbl = dialog.fields_dict.shed_production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Animal Products',
                        filters: { product_tied_to_which_animal: animal },
                        fields: ['name', 'default_unit_of_measure'],
                        limit_page_length: 500
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (grid) grid.refresh();
                            frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' }, 5);
                            return;
                        }

                        const products = r.message;
                        const rows = products.map(p => ({
                            pig_shed: '',
                            shed_info: '',
                            animal_product: p.name,
                            default_uom: p.default_unit_of_measure || '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── When animal changes ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="animal"]', function () {
                const animal = $(this).val();
                set_product_query_for_animal(animal);

                const tbl = dialog.fields_dict.production_table;
                const shed_tbl = dialog.fields_dict.shed_production_table;

                const is_pig_animal = ['Pig'].includes(animal);
                const is_animal_specific = dialog.get_value('is_animal_specific');

                dialog.set_value('pig', '');
                dialog.set_value('pig_shed', '');

                if (!animal) {
                    if (tbl) { tbl.df.data = []; if (tbl.grid) tbl.grid.refresh(); }
                    if (shed_tbl) { shed_tbl.df.data = []; if (shed_tbl.grid) shed_tbl.grid.refresh(); }
                    return;
                }

                if (is_animal_specific) {
                    if (is_pig_animal) {
                        populate_rows_for_all_pig();
                    } else {
                        populate_rows_from_products_for_animal(animal);
                    }
                } else {
                    populate_shed_rows_from_products(animal);
                }
            });

            // ───── When checkbox modes change, repopulate accordingly ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="is_animal_specific"], input[data-fieldname="is_shed_specific"]', function () {
                setTimeout(function () {
                    const animal = dialog.get_value('animal');
                    if (!animal) return;
                    const is_animal_specific = dialog.get_value('is_animal_specific');
                    const is_pig_animal = ['Pig'].includes(animal);

                    if (is_animal_specific) {
                        if (is_pig_animal) {
                            populate_rows_for_all_pig();
                        } else {
                            populate_rows_from_products_for_animal(animal);
                        }
                    } else {
                        populate_shed_rows_from_products(animal);
                    }
                }, 100);
            });

            // ───── If user selects a single pig in the top-level pig field ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="pig"]', function () {
                const selected_pig = $(this).val();
                const animal = dialog.get_value('animal');
                if (!selected_pig) return;
                if (!['Pig'].includes(animal)) return;

                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Pig', filters: { name: selected_pig }, fieldname: 'add_nickname_optional' },
                    callback: function (r) {
                        const nick = (r && r.message && r.message.add_nickname_optional) || '';
                        tbl.df.data = [{
                            pig: selected_pig,
                            pig_nickname: nick,
                            animal_product: '',
                            default_uom: '',
                            quantity_collected: 0.0
                        }];
                        if (tbl.grid) tbl.grid.refresh();

                        const grid = tbl.grid;
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows[0];
                                if (gr && gr.fields_map && gr.fields_map.pig) {
                                    gr.fields_map.pig.df.read_only = 1;
                                    gr.fields_map.pig.$input && gr.fields_map.pig.$input.prop('readonly', true);
                                    gr.toggle_remove_button && gr.toggle_remove_button(false);
                                }
                                if (gr && gr.fields_map && gr.fields_map.pig_nickname) {
                                    gr.fields_map.pig_nickname.df.read_only = 1;
                                    gr.fields_map.pig_nickname.$input && gr.fields_map.pig_nickname.$input.prop('readonly', true);
                                }
                            }
                            dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                        } catch (e) { console.warn('Could not lock single-pig row', e); }

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch pig nickname'), indicator: 'red' }, 10);
                    }
                });
            });

            // ───── When a pig_shed is selected in the shed table OR top-level, auto-fill shed_info ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="pig_shed"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;

                // Check if this is the top-level shed field
                const $row = $input.closest('.grid-row');
                if (!$row.length) {
                    // Top-level pig_shed selected — populate shed table with that shed
                    const tbl = dialog.fields_dict.shed_production_table;
                    if (!tbl) return;
                    frappe.call({
                        method: 'frappe.client.get_value',
                        args: { doctype: 'Pig Shed', filters: { name: val }, fieldname: ['shed_description', 'current_animal_count'] },
                        callback: function (r) {
                            const desc = (r && r.message && r.message.shed_description) || '';
                            const count = (r && r.message && r.message.current_animal_count) || '';
                            const info = desc + ' (' + count + ')';

                            // Get current animal for products
                            const animal = dialog.get_value('animal');
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Animal Products',
                                    filters: { product_tied_to_which_animal: animal },
                                    fields: ['name', 'default_unit_of_measure'],
                                    limit_page_length: 500
                                },
                                callback: function (pr) {
                                    if (!pr.message || !pr.message.length) {
                                        tbl.df.data = [{ pig_shed: val, shed_info: info, animal_product: '', default_uom: '', quantity_collected: 0.0 }];
                                        if (tbl.grid) tbl.grid.refresh();
                                        return;
                                    }
                                    const rows = pr.message.map(p => ({
                                        pig_shed: val,
                                        shed_info: info,
                                        animal_product: p.name,
                                        default_uom: p.default_unit_of_measure || '',
                                        quantity_collected: 0.0
                                    }));
                                    tbl.df.data = rows;
                                    if (tbl.grid) tbl.grid.refresh();
                                    set_product_query_for_animal(animal);
                                }
                            });
                        }
                    });
                    return;
                }

                // In-table pig_shed change — fill shed_info for that row
                const rowName = $row.attr('data-name');
                const tbl = dialog.fields_dict.shed_production_table;
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Pig Shed', filters: { name: val }, fieldname: ['shed_description', 'current_animal_count'] },
                    callback: function (r) {
                        const desc = (r && r.message && r.message.shed_description) || '';
                        const count = (r && r.message && r.message.current_animal_count) || '';
                        const info = desc + ' (' + count + ')';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.shed_info = info;
                                    if (gr.refresh_field) gr.refresh_field('shed_info');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set shed_info failed', e); }
                    }
                });
            });

            // ───── When an animal_product link is selected, auto-fill default_uom for that row ─────
            dialog.$wrapper.on('awesomplete-selectcomplete', 'input[data-fieldname="animal_product"]', function () {
                const $input = $(this);
                const val = $input.val();
                const $row = $input.closest('.grid-row');
                const rowName = $row.attr('data-name');

                // Determine which table this belongs to
                const is_shed_mode = dialog.get_value('is_shed_specific');
                const tbl = is_shed_mode ? dialog.fields_dict.shed_production_table : dialog.fields_dict.production_table;
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Animal Products', filters: { name: val }, fieldname: 'default_unit_of_measure' },
                    callback: function (r) {
                        const uom = (r && r.message && r.message.default_unit_of_measure) || '';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.default_uom = uom;
                                    if (gr.refresh_field) gr.refresh_field('default_uom');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set default_uom failed', e); }
                    }
                });
            });

            // ───── Newly added rows pick up the query for current animal ─────
            dialog.$wrapper.on('click', '.grid-add-row, .grid-add-rows, .grid-row-add', function () {
                setTimeout(function () {
                    const animal_val = dialog.get_value('animal');
                    set_product_query_for_animal(animal_val);
                }, 50);
            });

            // ───── Prevent future date on blur ─────
            dialog.$wrapper.on('blur', 'input[data-fieldname="date_of_collection"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;
                const today = frappe.datetime.get_today();
                if (val > today) {
                    frappe.show_alert({ message: __('Date of Collection cannot be a future date. The value has been reset to today.'), indicator: 'orange' }, 5);
                    dialog.set_value('date_of_collection', today);
                    $input.val(today);
                    try { $input.blur(); } catch (e) { }
                }
            });

            // ───── Initialize default queries for initial animal value ─────
            set_product_query_for_animal(dialog.get_value('animal'));
            const initial_animal = dialog.get_value('animal');
            if (['Pig'].includes(initial_animal)) {
                populate_rows_for_all_pig();
            } else if (initial_animal) {
                populate_rows_from_products_for_animal(initial_animal);
            }

        }).addClass('btn-primary');

        // ═══════════════════════════════════════════════════════════════════════
        // ──────── "Cull Animal?" Button ────────
        // ═══════════════════════════════════════════════════════════════════════
        list_view.page.add_inner_button(__('Cull Animal?'), () => {
            const today = frappe.datetime.get_today();

            // Fetch all active Pig (not culled)
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Pig',
                    filters: { has_been_culled: 0 },
                    fields: ['name', 'add_nickname_optional', 'pig_shed'],
                    limit_page_length: 2000
                },
                callback: function (r) {
                    const all_animals = (r && r.message) || [];
                    if (!all_animals.length) {
                        frappe.msgprint(__("No active Pig found to cull."));
                        return;
                    }

                    // Build initial HTML table
                    function build_animal_table(animals) {
                        if (!animals.length) {
                            return '<p class="text-muted">' + __("No animals match the current filters.") + '</p>';
                        }
                        let html = '<table class="table table-bordered table-hover" style="margin-top:10px;">';
                        html += '<thead><tr>';
                        html += '<th style="width:40px;"><input type="checkbox" class="cull-select-all"></th>';
                        html += '<th>' + __("Animal ID") + '</th>';
                        html += '<th>' + __("Nickname") + '</th>';
                        html += '<th>' + __("Shed") + '</th>';
                        html += '</tr></thead><tbody>';
                        animals.forEach(a => {
                            html += '<tr>';
                            html += '<td><input type="checkbox" class="cull-animal-check" data-animal="' + a.name + '"></td>';
                            html += '<td>' + a.name + '</td>';
                            html += '<td>' + (a.add_nickname_optional || '-') + '</td>';
                            html += '<td>' + (a.pig_shed || '-') + '</td>';
                            html += '</tr>';
                        });
                        html += '</tbody></table>';
                        return html;
                    }

                    const cull_dialog = new frappe.ui.Dialog({
                        title: __("Cull Animal"),
                        fields: [
                            {
                                fieldtype: 'Date',
                                fieldname: 'date_of_cull',
                                label: __('Date of Cull'),
                                default: today,
                                reqd: 1
                            },
                            { fieldtype: 'Column Break' },
                            {
                                fieldtype: 'Link',
                                fieldname: 'filter_shed',
                                label: __('Filter by Shed'),
                                options: 'Pig Shed'
                            },
                            {
                                fieldtype: 'Link',
                                fieldname: 'filter_animal',
                                label: __('Filter by Specific Animal'),
                                options: 'Pig',
                                get_query: function () {
                                    return { filters: { has_been_culled: 0 } };
                                }
                            },
                            { fieldtype: 'Section Break' },
                            {
                                fieldtype: 'HTML',
                                fieldname: 'animal_list_html',
                                label: __('Select Animals to Cull')
                            }
                        ],
                        size: 'large',
                        primary_action_label: __('Cull Selected'),
                        primary_action: function () {
                            const checked = cull_dialog.$wrapper.find('.cull-animal-check:checked');
                            if (!checked.length) {
                                frappe.msgprint(__("Please select at least one animal to cull."));
                                return;
                            }

                            const selected_animals = [];
                            checked.each(function () {
                                selected_animals.push($(this).data('animal'));
                            });

                            const date_val = cull_dialog.get_value('date_of_cull');

                            // ── Confirmation ──
                            frappe.confirm(
                                __("You are about to cull {0} animal(s). This action is IRREVERSIBLE and will also scrap any linked Assets. Are you sure?", [selected_animals.length]),
                                () => {
                                    frappe.call({
                                        method: 'farm_management_system.savanna_farm_suite.doctype.pig.pig.cull_animal',
                                        args: {
                                            animals: JSON.stringify(selected_animals),
                                            date_of_cull: date_val
                                        },
                                        freeze: true,
                                        freeze_message: __("Culling animals…"),
                                        callback: function (resp) {
                                            if (resp && !resp.exc) {
                                                try {
                                                    var audio = new Audio('/assets/farm_management_system/sounds/success.mp3');
                                                    audio.play();
                                                } catch (e) { }
                                                frappe.show_alert({ message: __("{0} animal(s) culled successfully", [selected_animals.length]), indicator: 'green' }, 5);
                                                cull_dialog.hide();
                                                list_view.refresh();
                                            } else {
                                                try {
                                                    var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                                    errAudio.play();
                                                } catch (e) { }
                                            }
                                        },
                                        error: function () {
                                            try {
                                                var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                                errAudio.play();
                                            } catch (e) { }
                                        }
                                    });
                                }
                            );
                        }
                    });

                    cull_dialog.show();
                    cull_dialog.$wrapper.find('.modal-dialog').css('max-width', '800px');

                    // Render initial table
                    const html_field = cull_dialog.fields_dict.animal_list_html;
                    html_field.$wrapper.html(build_animal_table(all_animals));

                    // Select-all checkbox
                    html_field.$wrapper.on('change', '.cull-select-all', function () {
                        const is_checked = $(this).prop('checked');
                        html_field.$wrapper.find('.cull-animal-check').prop('checked', is_checked);
                    });

                    // Filter logic
                    function apply_filters() {
                        const shed_val = cull_dialog.get_value('filter_shed');
                        const animal_val = cull_dialog.get_value('filter_animal');

                        let filtered = all_animals;
                        if (shed_val) {
                            filtered = filtered.filter(a => a.pig_shed === shed_val);
                        }
                        if (animal_val) {
                            filtered = filtered.filter(a => a.name === animal_val);
                        }
                        html_field.$wrapper.html(build_animal_table(filtered));
                    }

                    cull_dialog.fields_dict.filter_shed.df.onchange = apply_filters;
                    cull_dialog.fields_dict.filter_animal.df.onchange = apply_filters;
                }
            });
        });
    }
};

// farm_management_system/savanna_farm_suite/doctype/rabbit/rabbit_list.js
frappe.listview_settings['Rabbit'] = {
    refresh: function (list_view) {
        list_view.page.add_inner_button(__('Make Collection'), () => {
            const dialog = new frappe.ui.Dialog({
                title: __('Make a Collection of Animal Products'),
                fields: [
                    { fieldtype: 'Date', fieldname: 'date_of_collection', label: __('Date of Collection'), default: frappe.datetime.get_today(), reqd: 1 },
                    { fieldtype: 'Link', fieldname: 'animal', label: __('Specify Animal'), options: 'Animals', default: "Rabbit", reqd: 1 },
                    { fieldtype: 'Check', fieldname: 'is_animal_specific', label: __('Is Animal Specific?'), default: 1 },
                    { fieldtype: 'Check', fieldname: 'is_shed_specific', label: __('Is Shed Specific?'), default: 0 },
                    { fieldtype: 'Link', fieldname: 'rabbit', label: __('Specify Rabbit'), options: 'Rabbit', description: __('NOTE: Only Use for a single Rabbit if Applicable.'), depends_on: 'eval:doc.is_animal_specific==1' },
                    { fieldtype: 'Link', fieldname: 'rabbit_shed', label: __('Specify Rabbit Shed'), options: 'Rabbit Shed', description: __('Select a shed to collect for ALL rabbit in it.'), depends_on: 'eval:doc.is_shed_specific==1' },
                    {
                        fieldtype: 'Table',
                        fieldname: 'production_table',
                        label: __('Collections Table'),
                        description: __('Use this table for <b>Multiple Entries</b>'),
                        depends_on: 'eval:doc.is_animal_specific==1',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'rabbit', label: __('Rabbit'), options: 'Rabbit', in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'rabbit_nickname', label: __('Nickname'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'default_uom', label: __('Default UOM'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_collected', label: __('Quantity Collected'), reqd: 1, in_list_view: 1 }
                        ]
                    },
                    {
                        fieldtype: 'Table',
                        fieldname: 'shed_production_table',
                        label: __('Shed Collections Table'),
                        description: __('Use this table for <b>Shed-based Entries</b>'),
                        depends_on: 'eval:doc.is_shed_specific==1',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'rabbit_shed', label: __('Rabbit Shed'), options: 'Rabbit Shed', in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'shed_info', label: __('Shed Info'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'default_uom', label: __('Default UOM'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_collected', label: __('Quantity Collected'), reqd: 1, in_list_view: 1 }
                        ]
                    }
                ],
                primary_action_label: __('Make Entry'),
                primary_action: function () {
                    const dvalues = dialog.get_values(true);
                    const today = frappe.datetime.get_today();
                    const selected_date = dvalues && dvalues.date_of_collection;
                    if (selected_date && selected_date > today) {
                        frappe.show_alert({ message: __('Date of Collection cannot be a future date.'), indicator: 'orange' }, 5);
                        return;
                    }

                    const is_shed = dvalues.is_shed_specific;
                    const rows = is_shed ? (dvalues.shed_production_table || []) : (dvalues.production_table || []);
                    if (!rows.length) {
                        frappe.show_alert({ message: __('No products found to collect.'), indicator: 'orange' }, 5);
                        return;
                    }

                    frappe.warn(
                        __('Are you sure you want to proceed?'),
                        __('Please Note this Action is Irreversible'),
                        () => {
                            frappe.dom.freeze(__('Creating collection...'));
                            frappe.call({
                                method: 'farm_management_system.savanna_farm_suite.doctype.rabbit.rabbit.create_collection_entry',
                                args: {
                                    rabbit: is_shed ? null : (dvalues.rabbit || null),
                                    date_of_collection: dvalues.date_of_collection,
                                    rows: rows
                                },
                                callback: function (r) {
                                    frappe.dom.unfreeze();
                                    if (!r.exc && r.message) {
                                        // Play custom success sound
                                        var audio = new Audio('/assets/farm_management_system/sounds/success.mp3');
                                        audio.play().catch(function () { frappe.utils.play_sound('submit'); });
                                        dialog.hide();
                                        list_view.refresh();
                                        frappe.show_alert({ message: __('Collection recorded'), indicator: 'green' }, 5);
                                    } else if (r.exc) {
                                        // Play custom error sound
                                        var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                        errAudio.play().catch(function () { });
                                        const errMsg = (typeof r.exc === 'string') ? r.exc : (r._server_messages || r.exc || __('Unknown error occurred'));
                                        frappe.show_alert({ message: __('Error: ') + errMsg, indicator: 'red' }, 10);
                                    }
                                },
                                error: function () {
                                    frappe.dom.unfreeze();
                                    // Play custom error sound
                                    var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                    errAudio.play().catch(function () { });
                                    frappe.show_alert({ message: __('Network Error: Please try again.'), indicator: 'red' }, 10);
                                }
                            });
                        },
                        'Continue',
                        true
                    );
                }
            });

            dialog.show();
            dialog.$wrapper.find('.modal-dialog').addClass('modal-lg');

            // ───── Mutual exclusion for checkboxes ─────
            dialog.fields_dict.is_animal_specific.$input.on('change', function () {
                if (dialog.get_value('is_animal_specific')) {
                    dialog.set_value('is_shed_specific', 0);
                }
            });
            dialog.fields_dict.is_shed_specific.$input.on('change', function () {
                if (dialog.get_value('is_shed_specific')) {
                    dialog.set_value('is_animal_specific', 0);
                }
            });

            // ───── Helper: apply per-row + top-level query so animal_product only shows products for selected animal ─────
            function set_product_query_for_animal(animal_name) {
                const get_query_fn = function () {
                    if (!animal_name) return { filters: {} };
                    return { filters: { product_tied_to_which_animal: animal_name } };
                };

                // Apply to animal-specific table
                _apply_product_query_to_table(dialog.fields_dict.production_table, get_query_fn);
                // Apply to shed-specific table
                _apply_product_query_to_table(dialog.fields_dict.shed_production_table, get_query_fn);
            }

            function _apply_product_query_to_table(tbl, get_query_fn) {
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                try {
                    if (typeof grid.get_field === 'function') {
                        const topField = grid.get_field('animal_product');
                        if (topField) {
                            topField.get_query = get_query_fn;
                            if (topField.df) topField.df.get_query = get_query_fn;
                        }
                    }
                } catch (e) { console.warn('set_product_query top set failed', e); }

                try {
                    (grid.grid_rows || []).forEach(function (gr) {
                        try {
                            const f = gr.fields_map && gr.fields_map.animal_product;
                            if (f) {
                                f.get_query = get_query_fn;
                                if (f.df) f.df.get_query = get_query_fn;
                                if (gr.doc && gr.doc.animal_product) {
                                    gr.doc.animal_product = '';
                                    if (gr.refresh_field) gr.refresh_field('animal_product');
                                }
                            }
                        } catch (inner) { /* ignore per-row errors */ }
                    });
                } catch (e) { console.warn('set_product_query per-row set failed', e); }

                try { grid.refresh(); } catch (e) { }
            }

            // ───── Helper: populate rows for all active rabbit (has_been_culled == 0) ─────
            function populate_rows_for_all_rabbit() {
                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Rabbit',
                        filters: { has_been_culled: 0 },
                        fields: ['name', 'add_nickname_optional'],
                        limit_page_length: 2000
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (tbl.grid) tbl.grid.refresh();
                            frappe.show_alert({ message: __('No active Rabbit found'), indicator: 'orange' }, 5);
                            return;
                        }

                        const rows = r.message.map(c => ({
                            rabbit: c.name,
                            rabbit_nickname: c.add_nickname_optional || '',
                            animal_product: '',
                            default_uom: '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                grid.grid_rows.forEach(function (gr) {
                                    try {
                                        if (gr.fields_map && gr.fields_map.rabbit) {
                                            gr.fields_map.rabbit.df.read_only = 1;
                                            gr.fields_map.rabbit.$input && gr.fields_map.rabbit.$input.prop('readonly', true);
                                        }
                                        if (gr.fields_map && gr.fields_map.rabbit_nickname) {
                                            gr.fields_map.rabbit_nickname.df.read_only = 1;
                                            gr.fields_map.rabbit_nickname.$input && gr.fields_map.rabbit_nickname.$input.prop('readonly', true);
                                        }
                                        gr.toggle_remove_button && gr.toggle_remove_button(false);
                                    } catch (e) { }
                                });
                            }
                            dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                        } catch (e) {
                            console.warn('Could not lock child rows after rabbit populate', e);
                        }

                        set_product_query_for_animal(dialog.get_value('animal'));
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Rabbit'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── Helper: populate rows from list of Animal Products (one row per product) ─────
            function populate_rows_from_products_for_animal(animal) {
                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Animal Products',
                        filters: { product_tied_to_which_animal: animal },
                        fields: ['name', 'default_unit_of_measure'],
                        limit_page_length: 500
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (grid) grid.refresh();
                            frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' }, 5);
                            return;
                        }

                        const products = r.message;
                        const rows = products.map(p => ({
                            rabbit: '',
                            rabbit_nickname: '',
                            animal_product: p.name,
                            default_uom: p.default_unit_of_measure || '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').show();
                        if (grid.grid_rows && grid.grid_rows.length) {
                            grid.grid_rows.forEach(function (gr) {
                                try {
                                    if (gr.fields_map && gr.fields_map.rabbit) {
                                        gr.fields_map.rabbit.df.read_only = 0;
                                        gr.fields_map.rabbit.$input && gr.fields_map.rabbit.$input.prop('readonly', false);
                                        gr.toggle_remove_button && gr.toggle_remove_button(true);
                                    }
                                    if (gr.fields_map && gr.fields_map.rabbit_nickname) {
                                        gr.fields_map.rabbit_nickname.df.read_only = 1;
                                        gr.fields_map.rabbit_nickname.$input && gr.fields_map.rabbit_nickname.$input.prop('readonly', true);
                                    }
                                } catch (e) { }
                            });
                        }

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── Helper: populate shed table rows from products ─────
            function populate_shed_rows_from_products(animal) {
                const tbl = dialog.fields_dict.shed_production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Animal Products',
                        filters: { product_tied_to_which_animal: animal },
                        fields: ['name', 'default_unit_of_measure'],
                        limit_page_length: 500
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (grid) grid.refresh();
                            frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' }, 5);
                            return;
                        }

                        const products = r.message;
                        const rows = products.map(p => ({
                            rabbit_shed: '',
                            shed_info: '',
                            animal_product: p.name,
                            default_uom: p.default_unit_of_measure || '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── When animal changes ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="animal"]', function () {
                const animal = $(this).val();
                set_product_query_for_animal(animal);

                const tbl = dialog.fields_dict.production_table;
                const shed_tbl = dialog.fields_dict.shed_production_table;

                const is_rabbit_animal = ['Rabbit'].includes(animal);
                const is_animal_specific = dialog.get_value('is_animal_specific');

                dialog.set_value('rabbit', '');
                dialog.set_value('rabbit_shed', '');

                if (!animal) {
                    if (tbl) { tbl.df.data = []; if (tbl.grid) tbl.grid.refresh(); }
                    if (shed_tbl) { shed_tbl.df.data = []; if (shed_tbl.grid) shed_tbl.grid.refresh(); }
                    return;
                }

                if (is_animal_specific) {
                    if (is_rabbit_animal) {
                        populate_rows_for_all_rabbit();
                    } else {
                        populate_rows_from_products_for_animal(animal);
                    }
                } else {
                    populate_shed_rows_from_products(animal);
                }
            });

            // ───── When checkbox modes change, repopulate accordingly ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="is_animal_specific"], input[data-fieldname="is_shed_specific"]', function () {
                setTimeout(function () {
                    const animal = dialog.get_value('animal');
                    if (!animal) return;
                    const is_animal_specific = dialog.get_value('is_animal_specific');
                    const is_rabbit_animal = ['Rabbit'].includes(animal);

                    if (is_animal_specific) {
                        if (is_rabbit_animal) {
                            populate_rows_for_all_rabbit();
                        } else {
                            populate_rows_from_products_for_animal(animal);
                        }
                    } else {
                        populate_shed_rows_from_products(animal);
                    }
                }, 100);
            });

            // ───── If user selects a single rabbit in the top-level rabbit field ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="rabbit"]', function () {
                const selected_rabbit = $(this).val();
                const animal = dialog.get_value('animal');
                if (!selected_rabbit) return;
                if (!['Rabbit'].includes(animal)) return;

                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Rabbit', filters: { name: selected_rabbit }, fieldname: 'add_nickname_optional' },
                    callback: function (r) {
                        const nick = (r && r.message && r.message.add_nickname_optional) || '';
                        tbl.df.data = [{
                            rabbit: selected_rabbit,
                            rabbit_nickname: nick,
                            animal_product: '',
                            default_uom: '',
                            quantity_collected: 0.0
                        }];
                        if (tbl.grid) tbl.grid.refresh();

                        const grid = tbl.grid;
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows[0];
                                if (gr && gr.fields_map && gr.fields_map.rabbit) {
                                    gr.fields_map.rabbit.df.read_only = 1;
                                    gr.fields_map.rabbit.$input && gr.fields_map.rabbit.$input.prop('readonly', true);
                                    gr.toggle_remove_button && gr.toggle_remove_button(false);
                                }
                                if (gr && gr.fields_map && gr.fields_map.rabbit_nickname) {
                                    gr.fields_map.rabbit_nickname.df.read_only = 1;
                                    gr.fields_map.rabbit_nickname.$input && gr.fields_map.rabbit_nickname.$input.prop('readonly', true);
                                }
                            }
                            dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                        } catch (e) { console.warn('Could not lock single-rabbit row', e); }

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch rabbit nickname'), indicator: 'red' }, 10);
                    }
                });
            });

            // ───── When a rabbit_shed is selected in the shed table OR top-level, auto-fill shed_info ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="rabbit_shed"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;

                // Check if this is the top-level shed field
                const $row = $input.closest('.grid-row');
                if (!$row.length) {
                    // Top-level rabbit_shed selected — populate shed table with that shed
                    const tbl = dialog.fields_dict.shed_production_table;
                    if (!tbl) return;
                    frappe.call({
                        method: 'frappe.client.get_value',
                        args: { doctype: 'Rabbit Shed', filters: { name: val }, fieldname: ['shed_description', 'current_animal_count'] },
                        callback: function (r) {
                            const desc = (r && r.message && r.message.shed_description) || '';
                            const count = (r && r.message && r.message.current_animal_count) || '';
                            const info = desc + ' (' + count + ')';

                            // Get current animal for products
                            const animal = dialog.get_value('animal');
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Animal Products',
                                    filters: { product_tied_to_which_animal: animal },
                                    fields: ['name', 'default_unit_of_measure'],
                                    limit_page_length: 500
                                },
                                callback: function (pr) {
                                    if (!pr.message || !pr.message.length) {
                                        tbl.df.data = [{ rabbit_shed: val, shed_info: info, animal_product: '', default_uom: '', quantity_collected: 0.0 }];
                                        if (tbl.grid) tbl.grid.refresh();
                                        return;
                                    }
                                    const rows = pr.message.map(p => ({
                                        rabbit_shed: val,
                                        shed_info: info,
                                        animal_product: p.name,
                                        default_uom: p.default_unit_of_measure || '',
                                        quantity_collected: 0.0
                                    }));
                                    tbl.df.data = rows;
                                    if (tbl.grid) tbl.grid.refresh();
                                    set_product_query_for_animal(animal);
                                }
                            });
                        }
                    });
                    return;
                }

                // In-table rabbit_shed change — fill shed_info for that row
                const rowName = $row.attr('data-name');
                const tbl = dialog.fields_dict.shed_production_table;
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Rabbit Shed', filters: { name: val }, fieldname: ['shed_description', 'current_animal_count'] },
                    callback: function (r) {
                        const desc = (r && r.message && r.message.shed_description) || '';
                        const count = (r && r.message && r.message.current_animal_count) || '';
                        const info = desc + ' (' + count + ')';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.shed_info = info;
                                    if (gr.refresh_field) gr.refresh_field('shed_info');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set shed_info failed', e); }
                    }
                });
            });

            // ───── When an animal_product link is selected, auto-fill default_uom for that row ─────
            dialog.$wrapper.on('awesomplete-selectcomplete', 'input[data-fieldname="animal_product"]', function () {
                const $input = $(this);
                const val = $input.val();
                const $row = $input.closest('.grid-row');
                const rowName = $row.attr('data-name');

                // Determine which table this belongs to
                const is_shed_mode = dialog.get_value('is_shed_specific');
                const tbl = is_shed_mode ? dialog.fields_dict.shed_production_table : dialog.fields_dict.production_table;
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Animal Products', filters: { name: val }, fieldname: 'default_unit_of_measure' },
                    callback: function (r) {
                        const uom = (r && r.message && r.message.default_unit_of_measure) || '';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.default_uom = uom;
                                    if (gr.refresh_field) gr.refresh_field('default_uom');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set default_uom failed', e); }
                    }
                });
            });

            // ───── Newly added rows pick up the query for current animal ─────
            dialog.$wrapper.on('click', '.grid-add-row, .grid-add-rows, .grid-row-add', function () {
                setTimeout(function () {
                    const animal_val = dialog.get_value('animal');
                    set_product_query_for_animal(animal_val);
                }, 50);
            });

            // ───── Prevent future date on blur ─────
            dialog.$wrapper.on('blur', 'input[data-fieldname="date_of_collection"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;
                const today = frappe.datetime.get_today();
                if (val > today) {
                    frappe.show_alert({ message: __('Date of Collection cannot be a future date. The value has been reset to today.'), indicator: 'orange' }, 5);
                    dialog.set_value('date_of_collection', today);
                    $input.val(today);
                    try { $input.blur(); } catch (e) { }
                }
            });

            // ───── Initialize default queries for initial animal value ─────
            set_product_query_for_animal(dialog.get_value('animal'));
            const initial_animal = dialog.get_value('animal');
            if (['Rabbit'].includes(initial_animal)) {
                populate_rows_for_all_rabbit();
            } else if (initial_animal) {
                populate_rows_from_products_for_animal(initial_animal);
            }

        }).addClass('btn-primary');

        // ═══════════════════════════════════════════════════════════════════════
        // ──────── "Cull Animal?" Button ────────
        // ═══════════════════════════════════════════════════════════════════════
        list_view.page.add_inner_button(__('Cull Animal?'), () => {
            const today = frappe.datetime.get_today();

            // Fetch all active Rabbit (not culled)
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Rabbit',
                    filters: { has_been_culled: 0 },
                    fields: ['name', 'add_nickname_optional', 'rabbit_shed'],
                    limit_page_length: 2000
                },
                callback: function (r) {
                    const all_animals = (r && r.message) || [];
                    if (!all_animals.length) {
                        frappe.msgprint(__("No active Rabbit found to cull."));
                        return;
                    }

                    // Build initial HTML table
                    function build_animal_table(animals) {
                        if (!animals.length) {
                            return '<p class="text-muted">' + __("No animals match the current filters.") + '</p>';
                        }
                        let html = '<table class="table table-bordered table-hover" style="margin-top:10px;">';
                        html += '<thead><tr>';
                        html += '<th style="width:40px;"><input type="checkbox" class="cull-select-all"></th>';
                        html += '<th>' + __("Animal ID") + '</th>';
                        html += '<th>' + __("Nickname") + '</th>';
                        html += '<th>' + __("Shed") + '</th>';
                        html += '</tr></thead><tbody>';
                        animals.forEach(a => {
                            html += '<tr>';
                            html += '<td><input type="checkbox" class="cull-animal-check" data-animal="' + a.name + '"></td>';
                            html += '<td>' + a.name + '</td>';
                            html += '<td>' + (a.add_nickname_optional || '-') + '</td>';
                            html += '<td>' + (a.rabbit_shed || '-') + '</td>';
                            html += '</tr>';
                        });
                        html += '</tbody></table>';
                        return html;
                    }

                    const cull_dialog = new frappe.ui.Dialog({
                        title: __("Cull Animal"),
                        fields: [
                            {
                                fieldtype: 'Date',
                                fieldname: 'date_of_cull',
                                label: __('Date of Cull'),
                                default: today,
                                reqd: 1
                            },
                            { fieldtype: 'Column Break' },
                            {
                                fieldtype: 'Link',
                                fieldname: 'filter_shed',
                                label: __('Filter by Shed'),
                                options: 'Rabbit Shed'
                            },
                            {
                                fieldtype: 'Link',
                                fieldname: 'filter_animal',
                                label: __('Filter by Specific Animal'),
                                options: 'Rabbit',
                                get_query: function () {
                                    return { filters: { has_been_culled: 0 } };
                                }
                            },
                            { fieldtype: 'Section Break' },
                            {
                                fieldtype: 'HTML',
                                fieldname: 'animal_list_html',
                                label: __('Select Animals to Cull')
                            }
                        ],
                        size: 'large',
                        primary_action_label: __('Cull Selected'),
                        primary_action: function () {
                            const checked = cull_dialog.$wrapper.find('.cull-animal-check:checked');
                            if (!checked.length) {
                                frappe.msgprint(__("Please select at least one animal to cull."));
                                return;
                            }

                            const selected_animals = [];
                            checked.each(function () {
                                selected_animals.push($(this).data('animal'));
                            });

                            const date_val = cull_dialog.get_value('date_of_cull');

                            // ── Confirmation ──
                            frappe.confirm(
                                __("You are about to cull {0} animal(s). This action is IRREVERSIBLE and will also scrap any linked Assets. Are you sure?", [selected_animals.length]),
                                () => {
                                    frappe.call({
                                        method: 'farm_management_system.savanna_farm_suite.doctype.rabbit.rabbit.cull_animal',
                                        args: {
                                            animals: JSON.stringify(selected_animals),
                                            date_of_cull: date_val
                                        },
                                        freeze: true,
                                        freeze_message: __("Culling animals…"),
                                        callback: function (resp) {
                                            if (resp && !resp.exc) {
                                                try {
                                                    var audio = new Audio('/assets/farm_management_system/sounds/success.mp3');
                                                    audio.play();
                                                } catch (e) { }
                                                frappe.show_alert({ message: __("{0} animal(s) culled successfully", [selected_animals.length]), indicator: 'green' }, 5);
                                                cull_dialog.hide();
                                                list_view.refresh();
                                            } else {
                                                try {
                                                    var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                                    errAudio.play();
                                                } catch (e) { }
                                            }
                                        },
                                        error: function () {
                                            try {
                                                var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                                errAudio.play();
                                            } catch (e) { }
                                        }
                                    });
                                }
                            );
                        }
                    });

                    cull_dialog.show();
                    cull_dialog.$wrapper.find('.modal-dialog').css('max-width', '800px');

                    // Render initial table
                    const html_field = cull_dialog.fields_dict.animal_list_html;
                    html_field.$wrapper.html(build_animal_table(all_animals));

                    // Select-all checkbox
                    html_field.$wrapper.on('change', '.cull-select-all', function () {
                        const is_checked = $(this).prop('checked');
                        html_field.$wrapper.find('.cull-animal-check').prop('checked', is_checked);
                    });

                    // Filter logic
                    function apply_filters() {
                        const shed_val = cull_dialog.get_value('filter_shed');
                        const animal_val = cull_dialog.get_value('filter_animal');

                        let filtered = all_animals;
                        if (shed_val) {
                            filtered = filtered.filter(a => a.rabbit_shed === shed_val);
                        }
                        if (animal_val) {
                            filtered = filtered.filter(a => a.name === animal_val);
                        }
                        html_field.$wrapper.html(build_animal_table(filtered));
                    }

                    cull_dialog.fields_dict.filter_shed.df.onchange = apply_filters;
                    cull_dialog.fields_dict.filter_animal.df.onchange = apply_filters;
                }
            });
        });
    }
};

// farm_management_system/savanna_farm_suite/doctype/sheep/sheep_list.js
frappe.listview_settings['Sheep'] = {
    refresh: function (list_view) {
        list_view.page.add_inner_button(__('Make Collection'), () => {
            const dialog = new frappe.ui.Dialog({
                title: __('Make a Collection of Animal Products'),
                fields: [
                    { fieldtype: 'Date', fieldname: 'date_of_collection', label: __('Date of Collection'), default: frappe.datetime.get_today(), reqd: 1 },
                    { fieldtype: 'Link', fieldname: 'animal', label: __('Specify Animal'), options: 'Animals', default: "Sheep", reqd: 1 },
                    { fieldtype: 'Check', fieldname: 'is_animal_specific', label: __('Is Animal Specific?'), default: 1 },
                    { fieldtype: 'Check', fieldname: 'is_shed_specific', label: __('Is Shed Specific?'), default: 0 },
                    { fieldtype: 'Link', fieldname: 'sheep', label: __('Specify Sheep'), options: 'Sheep', description: __('NOTE: Only Use for a single Sheep if Applicable.'), depends_on: 'eval:doc.is_animal_specific==1' },
                    { fieldtype: 'Link', fieldname: 'sheep_shed', label: __('Specify Sheep Shed'), options: 'Sheep Shed', description: __('Select a shed to collect for ALL sheep in it.'), depends_on: 'eval:doc.is_shed_specific==1' },
                    {
                        fieldtype: 'Table',
                        fieldname: 'production_table',
                        label: __('Collections Table'),
                        description: __('Use this table for <b>Multiple Entries</b>'),
                        depends_on: 'eval:doc.is_animal_specific==1',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'sheep', label: __('Sheep'), options: 'Sheep', in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'sheep_nickname', label: __('Nickname'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'default_uom', label: __('Default UOM'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_collected', label: __('Quantity Collected'), reqd: 1, in_list_view: 1 }
                        ]
                    },
                    {
                        fieldtype: 'Table',
                        fieldname: 'shed_production_table',
                        label: __('Shed Collections Table'),
                        description: __('Use this table for <b>Shed-based Entries</b>'),
                        depends_on: 'eval:doc.is_shed_specific==1',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'sheep_shed', label: __('Sheep Shed'), options: 'Sheep Shed', in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'shed_info', label: __('Shed Info'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Data', fieldname: 'default_uom', label: __('Default UOM'), read_only: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_collected', label: __('Quantity Collected'), reqd: 1, in_list_view: 1 }
                        ]
                    }
                ],
                primary_action_label: __('Make Entry'),
                primary_action: function () {
                    const dvalues = dialog.get_values(true);
                    const today = frappe.datetime.get_today();
                    const selected_date = dvalues && dvalues.date_of_collection;
                    if (selected_date && selected_date > today) {
                        frappe.show_alert({ message: __('Date of Collection cannot be a future date.'), indicator: 'orange' }, 5);
                        return;
                    }

                    const is_shed = dvalues.is_shed_specific;
                    const rows = is_shed ? (dvalues.shed_production_table || []) : (dvalues.production_table || []);
                    if (!rows.length) {
                        frappe.show_alert({ message: __('No products found to collect.'), indicator: 'orange' }, 5);
                        return;
                    }

                    frappe.warn(
                        __('Are you sure you want to proceed?'),
                        __('Please Note this Action is Irreversible'),
                        () => {
                            frappe.dom.freeze(__('Creating collection...'));
                            frappe.call({
                                method: 'farm_management_system.savanna_farm_suite.doctype.sheep.sheep.create_collection_entry',
                                args: {
                                    sheep: is_shed ? null : (dvalues.sheep || null),
                                    date_of_collection: dvalues.date_of_collection,
                                    rows: rows
                                },
                                callback: function (r) {
                                    frappe.dom.unfreeze();
                                    if (!r.exc && r.message) {
                                        // Play custom success sound
                                        var audio = new Audio('/assets/farm_management_system/sounds/success.mp3');
                                        audio.play().catch(function () { frappe.utils.play_sound('submit'); });
                                        dialog.hide();
                                        list_view.refresh();
                                        frappe.show_alert({ message: __('Collection recorded'), indicator: 'green' }, 5);
                                    } else if (r.exc) {
                                        // Play custom error sound
                                        var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                        errAudio.play().catch(function () { });
                                        const errMsg = (typeof r.exc === 'string') ? r.exc : (r._server_messages || r.exc || __('Unknown error occurred'));
                                        frappe.show_alert({ message: __('Error: ') + errMsg, indicator: 'red' }, 10);
                                    }
                                },
                                error: function () {
                                    frappe.dom.unfreeze();
                                    // Play custom error sound
                                    var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                    errAudio.play().catch(function () { });
                                    frappe.show_alert({ message: __('Network Error: Please try again.'), indicator: 'red' }, 10);
                                }
                            });
                        },
                        'Continue',
                        true
                    );
                }
            });

            dialog.show();
            dialog.$wrapper.find('.modal-dialog').addClass('modal-lg');

            // ───── Mutual exclusion for checkboxes ─────
            dialog.fields_dict.is_animal_specific.$input.on('change', function () {
                if (dialog.get_value('is_animal_specific')) {
                    dialog.set_value('is_shed_specific', 0);
                }
            });
            dialog.fields_dict.is_shed_specific.$input.on('change', function () {
                if (dialog.get_value('is_shed_specific')) {
                    dialog.set_value('is_animal_specific', 0);
                }
            });

            // ───── Helper: apply per-row + top-level query so animal_product only shows products for selected animal ─────
            function set_product_query_for_animal(animal_name) {
                const get_query_fn = function () {
                    if (!animal_name) return { filters: {} };
                    return { filters: { product_tied_to_which_animal: animal_name } };
                };

                // Apply to animal-specific table
                _apply_product_query_to_table(dialog.fields_dict.production_table, get_query_fn);
                // Apply to shed-specific table
                _apply_product_query_to_table(dialog.fields_dict.shed_production_table, get_query_fn);
            }

            function _apply_product_query_to_table(tbl, get_query_fn) {
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                try {
                    if (typeof grid.get_field === 'function') {
                        const topField = grid.get_field('animal_product');
                        if (topField) {
                            topField.get_query = get_query_fn;
                            if (topField.df) topField.df.get_query = get_query_fn;
                        }
                    }
                } catch (e) { console.warn('set_product_query top set failed', e); }

                try {
                    (grid.grid_rows || []).forEach(function (gr) {
                        try {
                            const f = gr.fields_map && gr.fields_map.animal_product;
                            if (f) {
                                f.get_query = get_query_fn;
                                if (f.df) f.df.get_query = get_query_fn;
                                if (gr.doc && gr.doc.animal_product) {
                                    gr.doc.animal_product = '';
                                    if (gr.refresh_field) gr.refresh_field('animal_product');
                                }
                            }
                        } catch (inner) { /* ignore per-row errors */ }
                    });
                } catch (e) { console.warn('set_product_query per-row set failed', e); }

                try { grid.refresh(); } catch (e) { }
            }

            // ───── Helper: populate rows for all active sheep (has_been_culled == 0) ─────
            function populate_rows_for_all_sheep() {
                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Sheep',
                        filters: { has_been_culled: 0 },
                        fields: ['name', 'add_nickname_optional'],
                        limit_page_length: 2000
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (tbl.grid) tbl.grid.refresh();
                            frappe.show_alert({ message: __('No active Sheep found'), indicator: 'orange' }, 5);
                            return;
                        }

                        const rows = r.message.map(c => ({
                            sheep: c.name,
                            sheep_nickname: c.add_nickname_optional || '',
                            animal_product: '',
                            default_uom: '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                grid.grid_rows.forEach(function (gr) {
                                    try {
                                        if (gr.fields_map && gr.fields_map.sheep) {
                                            gr.fields_map.sheep.df.read_only = 1;
                                            gr.fields_map.sheep.$input && gr.fields_map.sheep.$input.prop('readonly', true);
                                        }
                                        if (gr.fields_map && gr.fields_map.sheep_nickname) {
                                            gr.fields_map.sheep_nickname.df.read_only = 1;
                                            gr.fields_map.sheep_nickname.$input && gr.fields_map.sheep_nickname.$input.prop('readonly', true);
                                        }
                                        gr.toggle_remove_button && gr.toggle_remove_button(false);
                                    } catch (e) { }
                                });
                            }
                            dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                        } catch (e) {
                            console.warn('Could not lock child rows after sheep populate', e);
                        }

                        set_product_query_for_animal(dialog.get_value('animal'));
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Sheep'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── Helper: populate rows from list of Animal Products (one row per product) ─────
            function populate_rows_from_products_for_animal(animal) {
                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Animal Products',
                        filters: { product_tied_to_which_animal: animal },
                        fields: ['name', 'default_unit_of_measure'],
                        limit_page_length: 500
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (grid) grid.refresh();
                            frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' }, 5);
                            return;
                        }

                        const products = r.message;
                        const rows = products.map(p => ({
                            sheep: '',
                            sheep_nickname: '',
                            animal_product: p.name,
                            default_uom: p.default_unit_of_measure || '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').show();
                        if (grid.grid_rows && grid.grid_rows.length) {
                            grid.grid_rows.forEach(function (gr) {
                                try {
                                    if (gr.fields_map && gr.fields_map.sheep) {
                                        gr.fields_map.sheep.df.read_only = 0;
                                        gr.fields_map.sheep.$input && gr.fields_map.sheep.$input.prop('readonly', false);
                                        gr.toggle_remove_button && gr.toggle_remove_button(true);
                                    }
                                    if (gr.fields_map && gr.fields_map.sheep_nickname) {
                                        gr.fields_map.sheep_nickname.df.read_only = 1;
                                        gr.fields_map.sheep_nickname.$input && gr.fields_map.sheep_nickname.$input.prop('readonly', true);
                                    }
                                } catch (e) { }
                            });
                        }

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── Helper: populate shed table rows from products ─────
            function populate_shed_rows_from_products(animal) {
                const tbl = dialog.fields_dict.shed_production_table;
                if (!tbl) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Animal Products',
                        filters: { product_tied_to_which_animal: animal },
                        fields: ['name', 'default_unit_of_measure'],
                        limit_page_length: 500
                    },
                    callback: function (r) {
                        if (!r.message || !r.message.length) {
                            tbl.df.data = [];
                            if (grid) grid.refresh();
                            frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' }, 5);
                            return;
                        }

                        const products = r.message;
                        const rows = products.map(p => ({
                            sheep_shed: '',
                            shed_info: '',
                            animal_product: p.name,
                            default_uom: p.default_unit_of_measure || '',
                            quantity_collected: 0.0
                        }));

                        tbl.df.data = rows;
                        if (grid) grid.refresh();

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' }, 10);
                    }
                });
            }

            // ───── When animal changes ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="animal"]', function () {
                const animal = $(this).val();
                set_product_query_for_animal(animal);

                const tbl = dialog.fields_dict.production_table;
                const shed_tbl = dialog.fields_dict.shed_production_table;

                const is_sheep_animal = ['Sheep'].includes(animal);
                const is_animal_specific = dialog.get_value('is_animal_specific');

                dialog.set_value('sheep', '');
                dialog.set_value('sheep_shed', '');

                if (!animal) {
                    if (tbl) { tbl.df.data = []; if (tbl.grid) tbl.grid.refresh(); }
                    if (shed_tbl) { shed_tbl.df.data = []; if (shed_tbl.grid) shed_tbl.grid.refresh(); }
                    return;
                }

                if (is_animal_specific) {
                    if (is_sheep_animal) {
                        populate_rows_for_all_sheep();
                    } else {
                        populate_rows_from_products_for_animal(animal);
                    }
                } else {
                    populate_shed_rows_from_products(animal);
                }
            });

            // ───── When checkbox modes change, repopulate accordingly ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="is_animal_specific"], input[data-fieldname="is_shed_specific"]', function () {
                setTimeout(function () {
                    const animal = dialog.get_value('animal');
                    if (!animal) return;
                    const is_animal_specific = dialog.get_value('is_animal_specific');
                    const is_sheep_animal = ['Sheep'].includes(animal);

                    if (is_animal_specific) {
                        if (is_sheep_animal) {
                            populate_rows_for_all_sheep();
                        } else {
                            populate_rows_from_products_for_animal(animal);
                        }
                    } else {
                        populate_shed_rows_from_products(animal);
                    }
                }, 100);
            });

            // ───── If user selects a single sheep in the top-level sheep field ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="sheep"]', function () {
                const selected_sheep = $(this).val();
                const animal = dialog.get_value('animal');
                if (!selected_sheep) return;
                if (!['Sheep'].includes(animal)) return;

                const tbl = dialog.fields_dict.production_table;
                if (!tbl) return;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Sheep', filters: { name: selected_sheep }, fieldname: 'add_nickname_optional' },
                    callback: function (r) {
                        const nick = (r && r.message && r.message.add_nickname_optional) || '';
                        tbl.df.data = [{
                            sheep: selected_sheep,
                            sheep_nickname: nick,
                            animal_product: '',
                            default_uom: '',
                            quantity_collected: 0.0
                        }];
                        if (tbl.grid) tbl.grid.refresh();

                        const grid = tbl.grid;
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows[0];
                                if (gr && gr.fields_map && gr.fields_map.sheep) {
                                    gr.fields_map.sheep.df.read_only = 1;
                                    gr.fields_map.sheep.$input && gr.fields_map.sheep.$input.prop('readonly', true);
                                    gr.toggle_remove_button && gr.toggle_remove_button(false);
                                }
                                if (gr && gr.fields_map && gr.fields_map.sheep_nickname) {
                                    gr.fields_map.sheep_nickname.df.read_only = 1;
                                    gr.fields_map.sheep_nickname.$input && gr.fields_map.sheep_nickname.$input.prop('readonly', true);
                                }
                            }
                            dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                        } catch (e) { console.warn('Could not lock single-sheep row', e); }

                        set_product_query_for_animal(animal);
                    },
                    error: function () {
                        frappe.show_alert({ message: __('Failed to fetch sheep nickname'), indicator: 'red' }, 10);
                    }
                });
            });

            // ───── When a sheep_shed is selected in the shed table OR top-level, auto-fill shed_info ─────
            dialog.$wrapper.on('change', 'input[data-fieldname="sheep_shed"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;

                // Check if this is the top-level shed field
                const $row = $input.closest('.grid-row');
                if (!$row.length) {
                    // Top-level sheep_shed selected — populate shed table with that shed
                    const tbl = dialog.fields_dict.shed_production_table;
                    if (!tbl) return;
                    frappe.call({
                        method: 'frappe.client.get_value',
                        args: { doctype: 'Sheep Shed', filters: { name: val }, fieldname: ['shed_description', 'current_animal_count'] },
                        callback: function (r) {
                            const desc = (r && r.message && r.message.shed_description) || '';
                            const count = (r && r.message && r.message.current_animal_count) || '';
                            const info = desc + ' (' + count + ')';

                            // Get current animal for products
                            const animal = dialog.get_value('animal');
                            frappe.call({
                                method: 'frappe.client.get_list',
                                args: {
                                    doctype: 'Animal Products',
                                    filters: { product_tied_to_which_animal: animal },
                                    fields: ['name', 'default_unit_of_measure'],
                                    limit_page_length: 500
                                },
                                callback: function (pr) {
                                    if (!pr.message || !pr.message.length) {
                                        tbl.df.data = [{ sheep_shed: val, shed_info: info, animal_product: '', default_uom: '', quantity_collected: 0.0 }];
                                        if (tbl.grid) tbl.grid.refresh();
                                        return;
                                    }
                                    const rows = pr.message.map(p => ({
                                        sheep_shed: val,
                                        shed_info: info,
                                        animal_product: p.name,
                                        default_uom: p.default_unit_of_measure || '',
                                        quantity_collected: 0.0
                                    }));
                                    tbl.df.data = rows;
                                    if (tbl.grid) tbl.grid.refresh();
                                    set_product_query_for_animal(animal);
                                }
                            });
                        }
                    });
                    return;
                }

                // In-table sheep_shed change — fill shed_info for that row
                const rowName = $row.attr('data-name');
                const tbl = dialog.fields_dict.shed_production_table;
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Sheep Shed', filters: { name: val }, fieldname: ['shed_description', 'current_animal_count'] },
                    callback: function (r) {
                        const desc = (r && r.message && r.message.shed_description) || '';
                        const count = (r && r.message && r.message.current_animal_count) || '';
                        const info = desc + ' (' + count + ')';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.shed_info = info;
                                    if (gr.refresh_field) gr.refresh_field('shed_info');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set shed_info failed', e); }
                    }
                });
            });

            // ───── When an animal_product link is selected, auto-fill default_uom for that row ─────
            dialog.$wrapper.on('awesomplete-selectcomplete', 'input[data-fieldname="animal_product"]', function () {
                const $input = $(this);
                const val = $input.val();
                const $row = $input.closest('.grid-row');
                const rowName = $row.attr('data-name');

                // Determine which table this belongs to
                const is_shed_mode = dialog.get_value('is_shed_specific');
                const tbl = is_shed_mode ? dialog.fields_dict.shed_production_table : dialog.fields_dict.production_table;
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Animal Products', filters: { name: val }, fieldname: 'default_unit_of_measure' },
                    callback: function (r) {
                        const uom = (r && r.message && r.message.default_unit_of_measure) || '';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.default_uom = uom;
                                    if (gr.refresh_field) gr.refresh_field('default_uom');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set default_uom failed', e); }
                    }
                });
            });

            // ───── Newly added rows pick up the query for current animal ─────
            dialog.$wrapper.on('click', '.grid-add-row, .grid-add-rows, .grid-row-add', function () {
                setTimeout(function () {
                    const animal_val = dialog.get_value('animal');
                    set_product_query_for_animal(animal_val);
                }, 50);
            });

            // ───── Prevent future date on blur ─────
            dialog.$wrapper.on('blur', 'input[data-fieldname="date_of_collection"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;
                const today = frappe.datetime.get_today();
                if (val > today) {
                    frappe.show_alert({ message: __('Date of Collection cannot be a future date. The value has been reset to today.'), indicator: 'orange' }, 5);
                    dialog.set_value('date_of_collection', today);
                    $input.val(today);
                    try { $input.blur(); } catch (e) { }
                }
            });

            // ───── Initialize default queries for initial animal value ─────
            set_product_query_for_animal(dialog.get_value('animal'));
            const initial_animal = dialog.get_value('animal');
            if (['Sheep'].includes(initial_animal)) {
                populate_rows_for_all_sheep();
            } else if (initial_animal) {
                populate_rows_from_products_for_animal(initial_animal);
            }

        }).addClass('btn-primary');

        // ═══════════════════════════════════════════════════════════════════════
        // ──────── "Cull Animal?" Button ────────
        // ═══════════════════════════════════════════════════════════════════════
        list_view.page.add_inner_button(__('Cull Animal?'), () => {
            const today = frappe.datetime.get_today();

            // Fetch all active Sheep (not culled)
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Sheep',
                    filters: { has_been_culled: 0 },
                    fields: ['name', 'add_nickname_optional', 'sheep_shed'],
                    limit_page_length: 2000
                },
                callback: function (r) {
                    const all_animals = (r && r.message) || [];
                    if (!all_animals.length) {
                        frappe.msgprint(__("No active Sheep found to cull."));
                        return;
                    }

                    // Build initial HTML table
                    function build_animal_table(animals) {
                        if (!animals.length) {
                            return '<p class="text-muted">' + __("No animals match the current filters.") + '</p>';
                        }
                        let html = '<table class="table table-bordered table-hover" style="margin-top:10px;">';
                        html += '<thead><tr>';
                        html += '<th style="width:40px;"><input type="checkbox" class="cull-select-all"></th>';
                        html += '<th>' + __("Animal ID") + '</th>';
                        html += '<th>' + __("Nickname") + '</th>';
                        html += '<th>' + __("Shed") + '</th>';
                        html += '</tr></thead><tbody>';
                        animals.forEach(a => {
                            html += '<tr>';
                            html += '<td><input type="checkbox" class="cull-animal-check" data-animal="' + a.name + '"></td>';
                            html += '<td>' + a.name + '</td>';
                            html += '<td>' + (a.add_nickname_optional || '-') + '</td>';
                            html += '<td>' + (a.sheep_shed || '-') + '</td>';
                            html += '</tr>';
                        });
                        html += '</tbody></table>';
                        return html;
                    }

                    const cull_dialog = new frappe.ui.Dialog({
                        title: __("Cull Animal"),
                        fields: [
                            {
                                fieldtype: 'Date',
                                fieldname: 'date_of_cull',
                                label: __('Date of Cull'),
                                default: today,
                                reqd: 1
                            },
                            { fieldtype: 'Column Break' },
                            {
                                fieldtype: 'Link',
                                fieldname: 'filter_shed',
                                label: __('Filter by Shed'),
                                options: 'Sheep Shed'
                            },
                            {
                                fieldtype: 'Link',
                                fieldname: 'filter_animal',
                                label: __('Filter by Specific Animal'),
                                options: 'Sheep',
                                get_query: function () {
                                    return { filters: { has_been_culled: 0 } };
                                }
                            },
                            { fieldtype: 'Section Break' },
                            {
                                fieldtype: 'HTML',
                                fieldname: 'animal_list_html',
                                label: __('Select Animals to Cull')
                            }
                        ],
                        size: 'large',
                        primary_action_label: __('Cull Selected'),
                        primary_action: function () {
                            const checked = cull_dialog.$wrapper.find('.cull-animal-check:checked');
                            if (!checked.length) {
                                frappe.msgprint(__("Please select at least one animal to cull."));
                                return;
                            }

                            const selected_animals = [];
                            checked.each(function () {
                                selected_animals.push($(this).data('animal'));
                            });

                            const date_val = cull_dialog.get_value('date_of_cull');

                            // ── Confirmation ──
                            frappe.confirm(
                                __("You are about to cull {0} animal(s). This action is IRREVERSIBLE and will also scrap any linked Assets. Are you sure?", [selected_animals.length]),
                                () => {
                                    frappe.call({
                                        method: 'farm_management_system.savanna_farm_suite.doctype.sheep.sheep.cull_animal',
                                        args: {
                                            animals: JSON.stringify(selected_animals),
                                            date_of_cull: date_val
                                        },
                                        freeze: true,
                                        freeze_message: __("Culling animals…"),
                                        callback: function (resp) {
                                            if (resp && !resp.exc) {
                                                try {
                                                    var audio = new Audio('/assets/farm_management_system/sounds/success.mp3');
                                                    audio.play();
                                                } catch (e) { }
                                                frappe.show_alert({ message: __("{0} animal(s) culled successfully", [selected_animals.length]), indicator: 'green' }, 5);
                                                cull_dialog.hide();
                                                list_view.refresh();
                                            } else {
                                                try {
                                                    var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                                    errAudio.play();
                                                } catch (e) { }
                                            }
                                        },
                                        error: function () {
                                            try {
                                                var errAudio = new Audio('/assets/farm_management_system/sounds/sfx.mp3');
                                                errAudio.play();
                                            } catch (e) { }
                                        }
                                    });
                                }
                            );
                        }
                    });

                    cull_dialog.show();
                    cull_dialog.$wrapper.find('.modal-dialog').css('max-width', '800px');

                    // Render initial table
                    const html_field = cull_dialog.fields_dict.animal_list_html;
                    html_field.$wrapper.html(build_animal_table(all_animals));

                    // Select-all checkbox
                    html_field.$wrapper.on('change', '.cull-select-all', function () {
                        const is_checked = $(this).prop('checked');
                        html_field.$wrapper.find('.cull-animal-check').prop('checked', is_checked);
                    });

                    // Filter logic
                    function apply_filters() {
                        const shed_val = cull_dialog.get_value('filter_shed');
                        const animal_val = cull_dialog.get_value('filter_animal');

                        let filtered = all_animals;
                        if (shed_val) {
                            filtered = filtered.filter(a => a.sheep_shed === shed_val);
                        }
                        if (animal_val) {
                            filtered = filtered.filter(a => a.name === animal_val);
                        }
                        html_field.$wrapper.html(build_animal_table(filtered));
                    }

                    cull_dialog.fields_dict.filter_shed.df.onchange = apply_filters;
                    cull_dialog.fields_dict.filter_animal.df.onchange = apply_filters;
                }
            });
        });
    }
};

// farm_management_system/public/js/poultry_batches_listview.js
frappe.listview_settings['Poultry Batches'] = {
    refresh: function (list_view) {
        // Add both actions under one grouped menu "Actions"
        // Use the third parameter (group) to place them together
        // Make Collection
        list_view.page.add_inner_button(__('Make Collection'), () => {
            const dialog = new frappe.ui.Dialog({
                title: __('Make Collection'),
                fields: [
                    {
                        fieldtype: 'Select',
                        fieldname: 'selection_mode',
                        label: __('Selection Mode'),
                        options: [
                            { label: __('Use Poultry Batch'), value: 'Batch' },
                            { label: __('Use Poultry Block'), value: 'Shed' }
                        ],
                        default: 'Batch'
                    },
                    {
                        fieldtype: 'Link',
                        fieldname: 'animal',
                        label: __('Specify Animal'),
                        options: 'Animals',
                        default: "Chicken",
                        depends_on: 'eval:doc.selection_mode == "Batch"',
                        reqd: 0 
                    },
                    {
                        fieldtype: 'Link',
                        fieldname: 'poultry_shed',
                        label: __('Specify Poultry Block'),
                        options: 'Poultry Shed',
                        depends_on: 'eval:doc.selection_mode == "Shed"',
                        onchange: function () {
                            const shed = this.get_value();
                            if (!shed) {
                                clear_production_table();
                                set_batch_query();
                                return;
                            }

                            frappe.db.get_value('Poultry Shed', shed, 'poultry_batch')
                                .then(r => {
                                    const batch = r && r.message && r.message.poultry_batch;
                                    set_batch_query_by_shed(shed);

                                    if (dialog.get_value('selection_mode') === 'Shed') {
                                        populate_rows_for_shed(batch, shed);
                                    }
                                });
                        }
                    },
                    {
                        fieldtype: 'Date',
                        fieldname: 'date_of_collection',
                        label: __('Date of Collection'),
                        default: frappe.datetime.get_today(),
                        reqd: 1
                    },
                    {
                        fieldtype: 'Table',
                        fieldname: 'production_table',
                        label: __('Collections Table'),
                        description: __('Use this table for <b>Multiple Entries</b>'),
                        depends_on: 'eval:doc.selection_mode=="Batch"',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'poultry_batch', label: __('Poultry Batch'), options: 'Poultry Batches', in_list_view: 1, reqd: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_normal', label: __('Normal Quantity'), in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_broken', label: __('Broken Quantity'), in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_abnormal', label: __('Abnormal Quantity'), in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_total', label: __('Total Quantity'), read_only: 1, in_list_view: 1 }
                        ]
                    },
                    {
                        fieldtype: 'Table',
                        fieldname: 'shed_production_table',
                        label: __('Shed Collections Table'),
                        description: __('Use this table for <b>Shed-based Entries</b>'),
                        depends_on: 'eval:doc.selection_mode=="Shed"',
                        fields: [
                            { fieldtype: 'Link', fieldname: 'poultry_shed', label: __('Block'), options: 'Poultry Shed', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Link', fieldname: 'animal_product', label: __('Animal Product'), options: 'Animal Products', reqd: 1, in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_normal', label: __('Normal'), in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_broken', label: __('Broken'), in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_abnormal', label: __('Abnormal'), in_list_view: 1 },
                            { fieldtype: 'Float', fieldname: 'quantity_total', label: __('Total'), read_only: 1, in_list_view: 1 }
                        ]
                    }
                ],
                primary_action_label: __('Make Entry'),
                primary_action: function () {
                    const dvalues = dialog.get_values(true);
                    const today = frappe.datetime.get_today();
                    const selected_date = dvalues && dvalues.date_of_collection;
                    if (selected_date && selected_date > today) {
                        frappe.show_alert({ message: __('Date of Collection cannot be a future date.'), indicator: 'red' }, 5);
                        return;
                    }

                    const rows = dvalues.selection_mode === 'Shed'
                        ? (dvalues.shed_production_table || [])
                        : (dvalues.production_table || []);

                    if (!rows.length) {
                        frappe.show_alert({ message: __('No products found to collect.'), indicator: 'orange' }, 5);
                        return;
                    }

                    if (dvalues.selection_mode === 'Shed' && !dvalues.poultry_shed) {
                        frappe.show_alert({ message: __('Please select a Poultry Shed for Shed mode.'), indicator: 'red' }, 5);
                        return;
                    }

                    const transformed_rows = [];
                    let has_valid_rows = false;

                    for (let row of rows) {
                        const normal_qty = getFloatValue(row.quantity_normal);
                        const broken_qty = getFloatValue(row.quantity_broken);
                        const abnormal_qty = getFloatValue(row.quantity_abnormal);
                        const total_qty = normal_qty + broken_qty + abnormal_qty;

                        if (total_qty <= 0) {
                            continue;
                        }

                        has_valid_rows = true;

                        if (!row.animal_product) {
                            frappe.show_alert({ message: __('Each row must include an Animal Product.'), indicator: 'red' }, 5);
                            return;
                        }

                       if (dvalues.selection_mode === 'Batch') {
                            const batch = row.poultry_batch;
                            if (!batch) {
                                frappe.show_alert({ message: __('Each row must include a Poultry Batch.'), indicator: 'red' }, 5);
                                return;
                            }
                        }

                        if (normal_qty > 0) {
                            transformed_rows.push({
                                poultry_batch: row.poultry_batch,
                                animal_product: row.animal_product,
                                default_uom: row.default_uom,
                                quantity_collected: normal_qty,
                                product_type: 'Whole'
                            });
                        }
                        if (broken_qty > 0) {
                            transformed_rows.push({
                                poultry_batch: row.poultry_batch,
                                animal_product: row.animal_product,
                                default_uom: row.default_uom,
                                quantity_collected: broken_qty,
                                product_type: 'Broken'
                            });
                        }
                        if (abnormal_qty > 0) {
                            transformed_rows.push({
                                poultry_batch: row.poultry_batch,
                                animal_product: row.animal_product,
                                default_uom: row.default_uom,
                                quantity_collected: abnormal_qty,
                                product_type: 'Abnormal'
                            });
                        }
                    }

                    if (!has_valid_rows) {
                        frappe.show_alert({ message: __('At least one row must have a quantity greater than 0.'), indicator: 'red' }, 5);
                        return;
                    }

                    const rows_to_send = transformed_rows;

                    frappe.warn(
                        __('Are you sure you want to proceed?'),
                        __('Please Note this Action is Irreversible'),
                        () => {
                            frappe.dom.freeze(__('Creating collection...'));
                            frappe.call({
                                method: 'farm_management_system.savanna_farm_suite.doctype.poultry_batches.poultry_batches.create_collection_entry',
                                args: {
                                    date_of_collection: dvalues.date_of_collection,
                                    selection_mode: dvalues.selection_mode,
                                    poultry_shed: dvalues.poultry_shed,
                                    rows: rows_to_send
                                },
                                callback: function (r) {
                                    frappe.dom.unfreeze();
                                    if (!r.exc && r.message) {
                                        frappe.utils.play_sound('success');
                                        dialog.hide();
                                        list_view.refresh();
                                        frappe.show_alert({ message: __('Collection recorded'), indicator: 'green' });
                                    } else if (r.exc) {
                                        frappe.show_alert({ message: __('Error: ') + (r.exc || __('Unknown error occurred')), indicator: 'red' }, 10);
                                    }
                                },
                                error: function () {
                                    frappe.dom.unfreeze();
                                    frappe.show_alert({ message: __('Network Error: Please try again.'), indicator: 'red' }, 10);
                                }
                            });
                        },
                        'Continue',
                        true
                    );
                }
            });

            dialog.show();
            dialog.$wrapper.find('.modal-dialog').addClass('modal-lg');


            // Set specific styles for the Make Entry button to match request
            const primary_btn = dialog.get_primary_btn();
            if (primary_btn) {
                primary_btn.css({
                    'background-color': '#14141f',
                    'color': 'white',
                    'font-weight': '800'
                });
            }

            // ---------- Helpers ----------
            function get_tbl() {
                const mode = dialog.get_value && dialog.get_value('selection_mode');
                if (mode === 'Shed') {
                    return dialog.fields_dict && dialog.fields_dict.shed_production_table;
                }
                return dialog.fields_dict && dialog.fields_dict.production_table;
            }

            function getFloatValue(value) {
                const n = parseFloat(value);
                return isNaN(n) ? 0.0 : n;
            }

            function refresh_row_totals(table) {
                if (!table || !table.df || !Array.isArray(table.df.data)) return;
                table.df.data.forEach(function (row) {
                    row.quantity_normal = getFloatValue(row.quantity_normal);
                    row.quantity_broken = getFloatValue(row.quantity_broken);
                    row.quantity_abnormal = getFloatValue(row.quantity_abnormal);
                    row.quantity_total = row.quantity_normal + row.quantity_broken + row.quantity_abnormal;
                });
                if (table.grid && table.grid.grid_rows) {
                    table.grid.grid_rows.forEach(function (gr) {
                        if (gr.doc && gr.refresh_field) gr.refresh_field('quantity_total');
                    });
                }
            }

            function refresh_current_table_totals() {
                refresh_row_totals(get_tbl());
            }

            // Ensure animal_product choices are filtered by product_tied_to_which_animal
            function set_product_query_for_animal(animal_name) {
                const tbl = get_tbl();
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                const get_query_fn = function () {
                    if (!animal_name) return { filters: {} };
                    return { filters: { product_tied_to_which_animal: animal_name } };
                };

                // Top-level grid field
                try {
                    const topField = grid.get_field('animal_product');
                    if (topField) {
                        topField.get_query = get_query_fn;
                        if (topField.df) topField.df.get_query = get_query_fn;
                    }
                } catch (e) { }

                // Per-row fields
                try {
                    (grid.grid_rows || []).forEach(function (gr) {
                        const f = gr.fields_map && gr.fields_map.animal_product;
                        if (f) {
                            f.get_query = get_query_fn;
                            if (f.df) f.df.get_query = get_query_fn;
                        }
                    });
                } catch (e) { }

                try { grid.refresh(); } catch (e) { }
            }

            // Set query for poultry_batch based on shed
            function set_batch_query_by_shed(shed_name) {
                const tbl = get_tbl();
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                const get_query_fn = function () {
                    if (!shed_name) return { filters: { batch_status: "Active" } };
                    return {
                        query: "farm_management_system.savanna_farm_suite.doctype.poultry_batches.poultry_batches.get_batches_for_shed",
                        filters: { shed: shed_name }
                    };
                };

                // Apply query to the table field
                try {
                    const topField = grid.get_field('poultry_batch');
                    if (topField) {
                        topField.get_query = get_query_fn;
                    }
                    (grid.grid_rows || []).forEach(gr => {
                        const f = gr.fields_map && gr.fields_map.poultry_batch;
                        if (f) f.get_query = get_query_fn;
                    });
                } catch (e) { }
            }

            function get_shed_batch(shed_name) {
                if (!shed_name) return Promise.resolve('');
                return frappe.db.get_value('Poultry Shed', shed_name, 'poultry_batch')
                    .then(r => (r && r.message && r.message.poultry_batch) || '');
            }

            // Populate rows dynamically for normal, broken, and abnormal eggs
            function populate_rows_for_shed(batch_name, shed_name) {
                const tbl = get_tbl();
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                if (!batch_name) {
                    clear_production_table();
                    frappe.show_alert({ message: __('Selected shed is not linked to an active batch.'), indicator: 'orange' }, 5);
                    return;
                }

                // Append a row for the selected shed and use separate quantity columns
                const rows = [
                    {
                        poultry_shed: shed_name,
                        poultry_batch: batch_name,
                        animal_product: 'Eggs',
                        default_uom: '',
                        quantity_normal: 0.0,
                        quantity_broken: 0.0,
                        quantity_abnormal: 0.0,
                        quantity_total: 0.0
                    }
                ];

                tbl.df.data = rows;
                grid.refresh();

                try {
                    (grid.grid_rows || []).forEach(function (gr) {
                        try {
                            gr.toggle_remove_button && gr.toggle_remove_button(false);
                            if(gr.fields_map) {
                                if(gr.fields_map.animal_product) gr.fields_map.animal_product.df.read_only = 1;
                                if(gr.fields_map.poultry_shed) gr.fields_map.poultry_shed.df.read_only = 1;
                                if(gr.fields_map.poultry_batch) gr.fields_map.poultry_batch.df.read_only = 1;
                            }
                        } catch (inner) { /* ignore */ }
                    });
                    dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                } catch (e) {
                    console.warn('populate_rows_for_shed: could not lock rows', e);
                }

                refresh_current_table_totals();

                frappe.db.get_value('Animal Products', 'Eggs', 'default_unit_of_measure')
                    .then(r => {
                        const uom = (r && r.message && r.message.default_unit_of_measure) || '';
                        tbl.df.data.forEach(row => row.default_uom = uom);
                        grid.refresh();
                    }).catch(() => { });
            }

            function set_batch_query() {
                const tbl = get_tbl();
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                const get_query_fn = function () {
                    return { filters: { batch_status: "Active" } };
                };

                try {
                    const topField = grid.get_field('poultry_batch');
                    if (topField) {
                        topField.get_query = get_query_fn;
                        if (topField.df) topField.df.get_query = get_query_fn;
                    }
                } catch (e) { console.warn('set_batch_query top set failed', e); }

                try {
                    (grid.grid_rows || []).forEach(function (gr) {
                        try {
                            const f = gr.fields_map && gr.fields_map.poultry_batch;
                            if (f) {
                                f.get_query = get_query_fn;
                                if (f.df) f.df.get_query = get_query_fn;
                            }
                        } catch (inner) { /* ignore per-row errors */ }
                    });
                } catch (e) { console.warn('set_batch_query per-row set failed', e); }

                try { grid.refresh(); } catch (e) { }
            }

            function clear_table(tbl) {
                if (!tbl) return;
                tbl.df.data = [];
                if (tbl.grid) tbl.grid.refresh();
            }

            function clear_production_table() {
                clear_table(dialog.fields_dict.production_table);
            }

            function clear_shed_production_table() {
                clear_table(dialog.fields_dict.shed_production_table);
            }

            function populate_rows_for_batches(batches) {
                const tbl = get_tbl();
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                tbl.df.data = [];
                grid.refresh();

                const rows = batches.map(b => ({
                    poultry_batch: b.name,
                    animal_product: '',
                    default_uom: '',
                    quantity_normal: 0.0,
                    quantity_broken: 0.0,
                    quantity_abnormal: 0.0,
                    quantity_total: 0.0
                }));

                tbl.df.data = rows;
                grid.refresh();

                refresh_current_table_totals();

                // Lock poultry_batch per row and hide add/remove controls
                try {
                    (grid.grid_rows || []).forEach(function (gr) {
                        try {
                            if (gr.fields_map && gr.fields_map.poultry_batch) {
                                gr.fields_map.poultry_batch.df && (gr.fields_map.poultry_batch.df.read_only = 1);
                                try { gr.fields_map.poultry_batch.$input && gr.fields_map.poultry_batch.$input.prop('readonly', true); } catch (e) { }
                            }

                            // hide remove button for this row
                            gr.toggle_remove_button && gr.toggle_remove_button(false);
                        } catch (inner) { /* ignore */ }
                    });

                    // hide global add-row controls so user cannot add rows
                    dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').hide();
                } catch (e) {
                    console.warn('populate_rows_for_batches: could not lock rows', e);
                }

                set_product_query_for_animal(dialog.get_value('animal'));
                set_batch_query();
            }

            function populate_rows_for_products(products) {
                const tbl = get_tbl();
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                tbl.df.data = [];
                grid.refresh();

                const rows = products.map(p => ({
                    poultry_batch: '',
                    animal_product: p.name,
                    default_uom: p.default_unit_of_measure || '',
                    quantity_normal: 0.0,
                    quantity_broken: 0.0,
                    quantity_abnormal: 0.0,
                    quantity_total: 0.0
                }));

                tbl.df.data = rows;
                grid.refresh();

                refresh_current_table_totals();

                try {
                    dialog.$wrapper.find('.grid-add-row, .grid-add-rows, .grid-row-add').show();
                    (grid.grid_rows || []).forEach(function (gr) {
                        try {
                            if (gr.fields_map && gr.fields_map.poultry_batch) {
                                gr.fields_map.poultry_batch.df && (gr.fields_map.poultry_batch.df.read_only = 0);
                                try { gr.fields_map.poultry_batch.$input && gr.fields_map.poultry_batch.$input.prop('readonly', false); } catch (e) { }
                                gr.toggle_remove_button && gr.toggle_remove_button(true);
                            }
                        } catch (inner) { /* ignore */ }
                    });
                } catch (e) {
                    console.warn('populate_rows_for_products: could not re-enable add/remove', e);
                }

                set_product_query_for_animal(dialog.get_value('animal'));
                set_batch_query();
            }

            // ---------- Events ----------

            // Initialize queries
            set_product_query_for_animal(null);
            set_batch_query();

            // Keep totals updated when quantity columns change
            dialog.$wrapper.on('change', 'input[data-fieldname="quantity_normal"], input[data-fieldname="quantity_broken"], input[data-fieldname="quantity_abnormal"]', function () {
                const $row = $(this).closest('.grid-row');
                const rowName = $row.attr('data-name');
                const tbl = get_tbl();
                if (!tbl || !tbl.grid) return;
                const gr = (tbl.grid.grid_rows || []).find(function (g) {
                    return g && g.wrapper && g.wrapper.attr && g.wrapper.attr('data-name') === rowName;
                });
                if (gr && gr.doc) {
                    gr.doc.quantity_normal = getFloatValue(gr.doc.quantity_normal);
                    gr.doc.quantity_broken = getFloatValue(gr.doc.quantity_broken);
                    gr.doc.quantity_abnormal = getFloatValue(gr.doc.quantity_abnormal);
                    gr.doc.quantity_total = gr.doc.quantity_normal + gr.doc.quantity_broken + gr.doc.quantity_abnormal;
                    gr.refresh_field && gr.refresh_field('quantity_total');
                }
            });

            // When animal changes
            dialog.$wrapper.on('change', 'input[data-fieldname="animal"]', function () {
                const animal = $(this).val();
                set_product_query_for_animal(animal);
                set_batch_query();

                const is_poultry = ['Chicken', 'Poultry', 'Birds'].includes(animal);
                clear_production_table();

                if (!animal) return;

                if (is_poultry) {
                    frappe.call({
                        method: 'frappe.client.get_list',
                        args: {
                            doctype: 'Poultry Batches',
                            filters: { batch_status: 'Active' },
                            fields: ['name'],
                            limit_page_length: 2000
                        },
                        callback: function (r) {
                            if (!r.message || !r.message.length) {
                                clear_production_table();
                                frappe.show_alert({ message: __('No active Poultry Batches found'), indicator: 'orange' });
                                return;
                            }
                            populate_rows_for_batches(r.message);
                        },
                        error: function () {
                            frappe.show_alert({ message: __('Failed to fetch Poultry Batches'), indicator: 'red' });
                        }
                    });
                } else {
                    frappe.call({
                        method: 'frappe.client.get_list',
                        args: {
                            doctype: 'Animal Products',
                            filters: { product_tied_to_which_animal: animal },
                            fields: ['name', 'default_unit_of_measure'],
                            limit_page_length: 1000
                        },
                        callback: function (r) {
                            if (!r.message || !r.message.length) {
                                clear_production_table();
                                frappe.show_alert({ message: __('No products found for selected animal'), indicator: 'orange' });
                                return;
                            }
                            populate_rows_for_products(r.message);
                        },
                        error: function () {
                            frappe.show_alert({ message: __('Failed to fetch Animal Products'), indicator: 'red' });
                        }
                    });
                }
            });

            // React to selection mode changes in the dialog
            dialog.$wrapper.on('change', 'input[data-fieldname="selection_mode"], select[data-fieldname="selection_mode"]', function () {
                const mode = $(this).val();
                const tbl = get_tbl();
                if (!tbl || !tbl.grid) return;

                if (mode === 'Shed') {
                    // Hide poultry batch dynamically in Shed (Block) Mode
                    tbl.grid.update_docfield_property('poultry_batch', 'hidden', 1);
                    tbl.grid.update_docfield_property('poultry_batch', 'in_list_view', 0);

                    clear_production_table();
                    clear_shed_production_table();
                    const shed = dialog.get_value('poultry_shed');
                    if (shed) {
                        frappe.db.get_value('Poultry Shed', shed, 'poultry_batch')
                            .then(r => {
                                const batch = r && r.message && r.message.poultry_batch;
                                populate_rows_for_shed(batch, shed);
                            });
                    }
                } else {
                    // Show poultry batch dynamically in Batch Mode
                    tbl.grid.update_docfield_property('poultry_batch', 'hidden', 0);
                    tbl.grid.update_docfield_property('poultry_batch', 'in_list_view', 1);
                    tbl.grid.update_docfield_property('poultry_shed', 'hidden', 1);
                    tbl.grid.update_docfield_property('poultry_shed', 'in_list_view', 0);

                    clear_production_table();
                    clear_shed_production_table();
                    const animal_field = dialog.$wrapper.find('input[data-fieldname="animal"]');
                    if (animal_field.length) {
                        animal_field.trigger('change');
                    }
                }

                tbl.grid.refresh();
            });

            // Auto-fill default_uom when product selected (awesomplete)
            dialog.$wrapper.on('awesomplete-selectcomplete', 'input[data-fieldname="animal_product"]', function () {
                const $input = $(this);
                const val = $input.val();
                const $row = $input.closest('.grid-row');
                const rowName = $row.attr('data-name');
                const tbl = get_tbl();
                if (!tbl || !tbl.grid) return;
                const grid = tbl.grid;

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: { doctype: 'Animal Products', filters: { name: val }, fieldname: 'default_unit_of_measure' },
                    callback: function (r) {
                        const uom = (r && r.message && r.message.default_unit_of_measure) || '';
                        try {
                            if (grid.grid_rows && grid.grid_rows.length) {
                                const gr = grid.grid_rows.find(function (rr) { return rr && rr.wrapper && rr.wrapper.attr && rr.wrapper.attr('data-name') === rowName; }) || grid.grid_rows[0];
                                if (gr && gr.doc) {
                                    gr.doc.default_uom = uom;
                                    if (gr.refresh_field) gr.refresh_field('default_uom');
                                } else {
                                    grid.refresh();
                                }
                            } else {
                                grid.refresh();
                            }
                        } catch (e) { console.warn('set default_uom failed', e); }
                    }
                });
            });

            // When user adds a row manually later, ensure queries are applied to new row
            dialog.$wrapper.on('click', '.grid-add-row, .grid-add-rows, .grid-row-add', function () {
                setTimeout(function () {
                    const animal_val = dialog.get_value('animal');
                    set_product_query_for_animal(animal_val);
                    set_batch_query();
                }, 50);
            });

            // Prevent future date on blur
            dialog.$wrapper.on('blur', 'input[data-fieldname="date_of_collection"]', function () {
                const $input = $(this);
                const val = $input.val();
                if (!val) return;
                const today = frappe.datetime.get_today();
                if (val > today) {
                    frappe.show_alert({ message: __('Date of Collection cannot be a future date. The value has been reset to today.'), indicator: 'orange' }, 5);
                    dialog.set_value('date_of_collection', today);
                    $input.val(today);
                    try { $input.blur(); } catch (e) { }
                }
            });

            // initialize based on initial animal value
            const initial_animal = dialog.get_value('animal');
            if (['Chicken', 'Poultry', 'Birds'].includes(initial_animal)) {
                frappe.timeout(0).then(function () {
                    dialog.$wrapper.find('input[data-fieldname="animal"]').trigger('change');
                });
            } else if (initial_animal) {
                dialog.$wrapper.find('input[data-fieldname="animal"]').trigger('change');
            }

        }, __('Actions')).addClass('btn-primary');

        // Cull Animals (under same Actions group)
        list_view.page.add_inner_button(__('Cull Animals'), () => {
            const checked = list_view.get_checked_items();
            const default_batch = (Array.isArray(checked) && checked.length === 1) ? checked[0] : '';

            const cull_dialog = new frappe.ui.Dialog({
                title: __('Cull Animals'),
                fields: [
                    { fieldtype: 'Link', fieldname: 'poultry_batch', label: __('Specify Poultry Batch'), options: 'Poultry Batches', reqd: 1, default: default_batch },
                    { fieldtype: 'Int', fieldname: 'current_count', label: __('Current Poultry Count'), read_only: 1, description: __('Autopopulated') },
                    { fieldtype: 'Int', fieldname: 'count', label: __('Number of chickens to cull'), reqd: 1, description: __('Enter a positive whole number (no decimals)'), placeholder: __('e.g. 2, 30') }
                ],
                primary_action_label: __('Cull'),
                primary_action: function (values) {
                    const batch = values.poultry_batch;
                    const count = parseInt(values.count, 10);
                    const current = parseInt(values.current_count || 0, 10);

                    if (!batch) {
                        frappe.show_alert({ message: __('Please specify a Poultry Batch.'), indicator: 'red' }, 6);
                        return;
                    }
                    if (isNaN(count) || count <= 0) {
                        frappe.show_alert({ message: __('Please enter a positive whole number for the count.'), indicator: 'red' }, 6);
                        return;
                    }
                    if (isNaN(current) || current < 0) {
                        frappe.show_alert({ message: __('Current Poultry Count is unavailable. Please check the selected batch.'), indicator: 'red' }, 8);
                        return;
                    }
                    if (count > current) {
                        frappe.show_alert({ message: __('Cull count ({0}) exceeds current poultry count ({1}).', [count, current]), indicator: 'red' }, 8);
                        return;
                    }

                    cull_dialog.hide();

                    frappe.confirm(
                        __('This Action is irreversible! Do you want to continue?'),
                        () => {
                            frappe.dom.freeze(__('Applying cull...'));

                            frappe.call({
                                method: 'farm_management_system.savanna_farm_suite.doctype.poultry_batches.poultry_batches.cull_poultry_batch',
                                args: {
                                    batch_name: batch,
                                    cull_count: count
                                },
                                callback: function (r) {
                                    frappe.dom.unfreeze();
                                    if (r.message && r.message.success) {
                                        frappe.utils.play_sound('success');
                                        frappe.show_alert({
                                            message: __(
                                                'Cull applied. Batch: {0}. New mortality_count: {1}, mortality_rate: {2}%',
                                                [batch, r.message.mortality_count, (r.message.mortality_rate || 0).toFixed(3)]
                                            ),
                                            indicator: 'green'
                                        }, 8);
                                        list_view.refresh();
                                    } else {
                                        const err = (r.message && r.message.error) || (r.exc ? r.exc : __('Unknown error'));
                                        frappe.show_alert({
                                            message: __('Error: {0}', [err]),
                                            indicator: 'red'
                                        }, 10);
                                    }
                                },
                                error: function () {
                                    frappe.dom.unfreeze();
                                    frappe.show_alert({
                                        message: __('Failed to call server'),
                                        indicator: 'red'
                                    }, 10);
                                }
                            });
                        },
                        () => {}
                    );
                }
            });

            function fetchAndSetCurrentCount(batch_name) {
                if (!batch_name) {
                    cull_dialog.set_value('current_count', '');
                    return;
                }

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: {
                        doctype: 'Poultry Batches',
                        filters: { name: batch_name },
                        fieldname: ['total_animals', 'mortality_count']
                    },
                    callback: function (r) {
                        if (!r || !r.message) {
                            cull_dialog.set_value('current_count', '');
                            frappe.show_alert({ message: __('Unable to fetch batch data.'), indicator: 'red' }, 6);
                            return;
                        }
                        const total = parseFloat(r.message.total_animals || 0);
                        const mort = parseFloat(r.message.mortality_count || 0);
                        let current = Math.max(0, Math.round(total - mort));
                        if (isNaN(current)) current = 0;
                        cull_dialog.set_value('current_count', current);
                    },
                    error: function () {
                        cull_dialog.set_value('current_count', '');
                        frappe.show_alert({ message: __('Network error fetching batch data.'), indicator: 'red' }, 8);
                    }
                });
            }

            cull_dialog.show();
            cull_dialog.$wrapper.find('.modal-dialog').addClass('modal-md');
            if (default_batch) {
                fetchAndSetCurrentCount(default_batch);
            }

            cull_dialog.$wrapper.on('change', 'input[data-fieldname="poultry_batch"]', function () {
                const batch = $(this).val();
                fetchAndSetCurrentCount(batch);
            });
            cull_dialog.$wrapper.on('awesomplete-selectcomplete', 'input[data-fieldname="poultry_batch"]', function () {
                const batch = $(this).val();
                fetchAndSetCurrentCount(batch);
            });

        }, __('Actions'));
    }
};
